Функция ПолучитьНоменклатуруИзВложенныхГрупп(Группа)
    // Массив для хранения элементов
    Элементы = Новый Массив;

    Процедура ОбходГруппы(Группа)
        ВыборкаПодчинённых = Группа.ПолучитьПодчиненные();

        Пока ВыборкаПодчинённых.Следующий() Цикл
            Если ТипЗнч(ВыборкаПодчинённых.ТекущийЭлемент()) = Тип("СправочникСсылка.Номенклатура") Тогда
                // Добавляем элемент в массив
                Элементы.Добавить(ВыборкаПодчинённых.ТекущийЭлемент());
            ИначеЕсли ТипЗнч(ВыборкаПодчинённых.ТекущийЭлемент()) = Тип("СправочникОбъект.Номенклатура") И 
                   ВыборкаПодчинённых.ТекущийЭлемент().ЭтоГруппа Тогда
                // Рекурсивно обходим подчинённые группы
                ОбходГруппы(ВыборкаПодчинённых.ТекущийЭлемент());
            КонецЕсли;  
        КонецЦикла;
    КонецПроцедуры;

    // Запускаем обход с переданной группы
    ОбходГруппы(Группа);

    // Сортируем элементы по наименованию
    Элементы.СортироватьПоНаименованию();

    Возврат Элементы;
