Функция ПроверитьНаличиеДругогоПоИНН(ИНН, КонтрагентИсключить)

	Если ТипЗнч(ИНН) <> Тип("Строка") Тогда
		ИНН = Строка(ИНН);
	КонецЕсли;
	ИНН = СокрЛП(СтрЗаменить(ИНН, " ", ""));
	Если ПустаяСтрока(ИНН) Тогда
		Возврат Ложь;
	КонецЕсли;

	Запрос = Новый Запрос;
	ТекстЗапроса = 
	"ВЫБРАТЬ ПЕРВЫЕ 1
		Контрагенты.Ссылка КАК Ссылка
	ИЗ
		Справочник.Контрагенты КАК Контрагенты
	ГДЕ
		Контрагенты.ИНН = &ИНН";
	Если ЗначениеЗаполнено(КонтрагентИсключить) Тогда
		ТекстЗапроса = ТекстЗапроса + "
		И Контрагенты.Ссылка <> &Исключить";
	КонецЕсли;

	Запрос.Текст = ТекстЗапроса;
	Запрос.УстановитьПараметр("ИНН", ИНН);
	Если ЗначениеЗаполнено(КонтрагентИсключить) Тогда
		Запрос.УстановитьПараметр("Исключить", КонтрагентИсключить);
	КонецЕсли;

	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();
	Если Выборка.Следующий() Тогда
		Возврат Истина;
	Иначе
		Возврат Ложь;
	КонецЕсли;

