Функция РассчитатьСвободныйОстаток(МассивНоменклатуры, Склад) Экспорт

    ТаблицаРезультата = Новый ТаблицаЗначений;
    ТаблицаРезультата.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    ТаблицаРезультата.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число"));

    // Получаем остатки из регистра
    Запрос = Новый Запрос;
    Запрос.Текст = "
        ВЫБРАТЬ
            ТоварыНаСкладах.Номенклатура КАК Номенклатура,
            ТоварыНаСкладах.ВНаличии КАК ВНаличии
        ИЗ
            РегистрНакопления.ТоварыНаСкладах.Остатки(&Период, Склад = &Склад И Номенклатура В (&МассивНоменклатуры)) КАК ТоварыНаСкладах
    ";
    Запрос.УстановитьПараметр("Период", Неопределено);
    Запрос.УстановитьПараметр("Склад", Склад);
    Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
    РезультатЗапроса = Запрос.Выполнить();
    Выборка = РезультатЗапроса.Выбрать();

    // Заполняем таблицу результатов, предполагая, что зарезервированного количества в текущей модели данных нет — считаем его нулевым
    Пока Выборка.Следующий() Цикл
        НоваяСтрока = ТаблицаРезультата.Добавить();
        НоваяСтрока.Номенклатура = Выборка.Номенклатура;
        НоваяСтрока.Свободно = Выборка.ВНаличии;
    КонецЦикла;

    // Добавляем товары из массива номенклатуры, которых не оказалось в остатках (у них и остаток, и резерв — нулевые)
    Для Каждого ТекущаяНоменклатура Из МассивНоменклатуры Цикл
        Если Не ТаблицаРезультата.НайтиСтроки(Новый Структура("Номенклатура", ТекущаяНоменклатура)).Количество() Тогда
            НоваяСтрока = ТаблицаРезультата.Добавить();
            НоваяСтрока.Номенклатура = ТекущаяНоменклатура;
            НоваяСтрока.Свободно = 0;
        КонецЕсли;
    КонецЦикла;

    Возврат ТаблицаРезультата;

КонецФункции
```

