Функция РассчитатьСвободныйОстаток(МассивНоменклатуры, Склад)

	ТаблицаРезультата = Новый ТаблицаЗначений;
	ТаблицаРезультата.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	ТаблицаРезультата.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число", 15, 3));

	Запрос = Новый Запрос;
	Запрос.Текст =
		"ВЫБРАТЬ
		|	ТоварыНаСкладах.Номенклатура,
		|	ТоварыНаСкладах.ВНаличии - ЕСТЬNULL(Резервы.Зарезервировано, 0) КАК Свободно
		|ИЗ
		|	РегистрНакопления.ТоварыНаСкладах КАК ТоварыНаСкладах
		|		ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.Резервы КАК Резервы
		|		ПО ТоварыНаСкладах.Номенклатура = Резервы.Номенклатура
		|		И ТоварыНаСкладах.Склад = Резервы.Склад
		|ГДЕ
		|	ТоварыНаСкладах.Склад = &Склад
		|	И ТоварыНаСкладах.Номенклатура В(&МассивНоменклатуры)";

	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);

	Выборка = Запрос.Выполнить().Выбрать();

	Пока Выборка.Следующий() Цикл
		НоваяСтрока = ТаблицаРезультата.Добавить();
		НоваяСтрока.Номенклатура = Выборка.Номенклатура;
		НоваяСтрока.Свободно = Выборка.Свободно;
	КонецЦикла;

	// Добавляем номенклатуру, которая есть в массиве, но отсутствует в ТоварахНаСкладах
	Для Каждого НоменклатураИзМассива Цикл
		Найден = Ложь;
		Для Каждого СтрокаРезультата Из ТаблицаРезультата Цикл
			Если СтрокаРезультата.Номенклатура = НоменклатураИзМассива Тогда
				Найден = Истина;
				Прервать;
			КонецЕсли;
		КонецЦикла;

		Если Не Найден Тогда
			НоваяСтрока = ТаблицаРезультата.Добавить();
			НоваяСтрока.Номенклатура = НоменклатураИзМассива;
			НоваяСтрока.Свободно = 0; // Если нет в наличии, то и свободно 0
		КонецЕсли;
	КонецЦикла;

	Возврат ТаблицаРезультата;

