Функция СвободныйОстатокТоваров(МассивНоменклатуры, Склад) Экспорт
    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    Результат.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число", , 15, 3));

    Если МассивНоменклатуры.Количество() = 0 Тогда
        Возврат Результат;
    КонецЕсли;

    Запрос = Новый Запрос;
    Запрос.МенеджерВременныхТаблиц = Новый МенеджерВременныхТаблиц;

    // Формируем временную таблицу с переданной номенклатурой
    ТЗНоменклатура = Новый ТаблицаЗначений;
    ТЗНоменклатура.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    Для Каждого Элемент Из МассивНоменклатуры Цикл
        СтрокаТЗ = ТЗНоменклатура.Добавить();
        СтрокаТЗ.Номенклатура = Элемент;
    КонецЦикла;

    Запрос.Текст = "ВЫБРАТЬ * ПОМЕСТИТЬ ВТ_Номенклатура ИЗ &ТЗНоменклатура КАК ТЗ";
    Запрос.УстановитьПараметр("ТЗНоменклатура", ТЗНоменклатура);
    Запрос.Выполнить();

    // Основной запрос для расчета свободного остатка
    Запрос.Текст = 
    "ВЫБРАТЬ
    |    ВТ_Номенклатура.Номенклатура,
    |    ЕСТЬNULL(Товары.ВНаличии, 0) - ЕСТЬNULL(Резервы.Зарезервировано, 0) КАК Свободно
    |ИЗ
    |    ВТ_Номенклатура КАК ВТ_Номенклатура
    |        ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.ТоварыНаСкладах.Остатки(, Склад = &Склад, Номенклатура В 
    |                (ВЫБРАТЬ ВТ_Номенклатура.Номенклатура ИЗ ВТ_Номенклатура)) КАК Товары
    |        ПО ВТ_Номенклатура.Номенклатура = Товары.Номенклатура
    |        ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.Резервы.Остатки(, Склад = &Склад, Номенклатура В 
    |                (ВЫБРАТЬ ВТ_Номенклатура.Номенклатура ИЗ ВТ_Номенклатура)) КАК Резервы
    |        ПО ВТ_Номенклатура.Номенклатура = Резервы.Номенклатура";

    Запрос.УстановитьПараметр("Склад", Склад);
    РезультатЗапроса = Запрос.Выполнить();
    Результат.Загрузить(РезультатЗапроса);

    Возврат Результат;
КонецФункции

Функция РасчетСвободногоОстатка(МассивНоменклатуры, Склад)

	ТаблицаРезультат = Новый ТаблицаЗначений;
	ТаблицаРезультат.Колонки.Добавить("Номенклатура");
	ТаблицаРезультат.Колонки.Добавить("Свободно");

	// Запрос для получения остатков из "ТоварыНаСкладах"
	Запрос1 = Новый Запрос;
	Запрос1.Текст = 
		"ВЫБРАТЬ
			|	ТоварыНаСкладах.Номенклатура,
			|	ТоварыНаСкладах.ВНаличии КАК ВНаличии
			|ИЗ
			|	РегистрНакопления.ТоварыНаСкладах КАК ТоварыНаСкладах
			|ГДЕ
			|	ТоварыНаСкладах.Склад = &Склад
			|	И ТоварыНаСкладах.Номенклатура В (&МассивНоменклатуры)
			|	И ТоварыНаСкладах.Период = 
			|		(ВЫБРАТЬ
			|			МАКСИМУМ(ТоварыНаСкладах.Период)
			|		ИЗ
			|			РегистрНакопления.ТоварыНаСкладах КАК ТНС
			|		ГДЕ
			|			ТНС.Склад = &Склад
			|			И ТНС.Номенклатура В (&МассивНоменклатуры))";
	Запрос1.УстановитьПараметр("Склад", Склад);
	Запрос1.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
	Результат1 = Запрос1.Выполнить();

	// Запрос для получения резервов
	Запрос2 = Новый Запрос;
	Запрос2.Текст = 
		"ВЫБРАТЬ
			|	Резервы.Номенклатура,
			|	Резервы.Зарезервировано
			|ИЗ
