Функция РассчитатьСвободныйОстаток(МассивНоменклатуры, Склад)
	ТаблицаРезультат = Новый ТаблицаЗначений;
	ТаблицаРезультат.Колонки.Добавить("Номенклатура", Тип("СправочникСсылка.Номенклатура"));
	ТаблицаРезультат.Колонки.Добавить("Свободно", Тип("Число"));

	// Получаем остатки товаров на складе
	Запрос = Новый Запрос;
	Запрос.Текст = "ВЫБРАТЬ 
		Остатки.Номенклатура,
		СУММА(Остатки.КоличествоОстаток) КАК КоличествоОстаток
	PO ИзмеренияОстатковСКладами.ОстаткиНКакКоличествоОстаток(Период(&КонецПериода), &Склад, , , ) КАК Остатки
	GРУППИРОВАТЬ ПО Остатки.Номенклатура";
	Запрос.УстановитьПараметр("КонецПериода", ДатаКонцаПериода());
	Запрос.УстановитьПараметр("Склад", Склад);
	РезультатОстатков = Запрос.Выполнить().Выгрузить();

	// Получаем зарезервированные товары
	Запрос = Новый Запрос;
	Запрос.Текст = "ВЫБРАТЬ 
		Резервы.Номенклатура,
		СУММА(Резервы.Количество) КАК КоличествоРезерв
	PO РегистрыНакопления.РезервированиеНКакКоличество(, , , , , , ) КАК Резервы
	GДЕ Резервы.Склад = &Склад
	И Резервы.Номенклатура В(&Номенклатура)
	GРУППИРОВАТЬ ПО Резервы.Номенклатура";
	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("Номенклатура", МассивНоменклатуры);
	РезультатРезервов = Запрос.Выполнить().Выгрузить();

	// Формируем итоговую таблицу
	Для Каждого СтрокаОстатков Из РезультатОстатков Цикл
		СтрокаРезерва = РезультатРезервов.Найти(СтрокаОстатков.Номенклатура);
		Если СтрокаРезерва = Неопределено Тогда
			КолРезерв = 0;
		Else
			КолРезерв = СтрокаРезерва.КоличествоРезерв;
		КонецЕсли;

		НоваяСтрока = ТаблицаРезультат.Добавить();
		НоваяСтрока.Номенклатура = СтрокаОстатков.Номенклатура;
		НоваяСтрока.Свободно = Макс(0, СтрокаОстатков.КоличествоОстаток - КолРезерв);
	КонецЦикла;

	Возврат ТаблицаРезультат;
КонецФункции

