        Номенклатура.РезервКоличество КАК Зарезервировано,  
        Номенклатура.ОстатокНАСкладе ПО СКЛАД КАК Наличие  
  ПОМЕСТИТЬ ИтоговыеДанные  
  ОБЪЕДИНИТЬ ВСЕ  
  ВЫБРАТЬ  
        Номенклатура.Код,  
        Номенклатура.Наименование,  
        Номенклатура.ВариантУпаковки,  
        Номенклатура.СвойствоКакСтрока  
  ИЗ  
        Справочник.Номенклатура  
  ГДЕ  
        НЕ Номенклатура.РезервКоличество ЕСТЬ NULL"; 
Если Не ПустаяСтрока(Склад) Тогда
    Запрос += " И Номенклатура.Склад = &Склад";
КонецЕсли;
Запрос += "  
  СОЕДИНИТЬ ПО Номенклатура.Код  
  КАК ИтоговыеДанные  
 ГДЕ  
        ИтоговыеДанные.Наличие <> 0"; 
РезультатЗапроса = ВыполнитьSQL(Запрос, Заместить( "&Склад", Строка(Склад), Истина));
Для Каждого СтрокаИзРезультата Из РезультатЗапроса Цикл
ТаблицаРезультат.ДобавитьСтроку();
ТаблицаРезультат.ТекущаяСтрока.Номенклатура = СтрокаИзРезультата.НоменклатураНаименование;
ТаблицаРезультат.ТекущаяСтрока.Свободно = СтрокаИзРезультата.Наличиев - СтрокаИзРезультата.Зарезервировано;
КонецЦикла;
Возврат ТаблицаРезультат;
