Функция РассчитатьСвободныйОстатокТоваровНаСкладе(МассивНоменклатуры, Склад) Экспорт

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	Результат.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 3)));

	Если МассивНоменклатуры = Неопределено Или МассивНоменклатуры.Количество() = 0 Тогда
		Возврат Результат;
	КонецЕсли;

	СписокНоменклатуры = Новый ТаблицаЗначений;
	СписокНоменклатуры.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));

	Для Каждого Номенклатура Из МассивНоменклатуры Цикл
		НоваяСтрока = СписокНоменклатуры.Добавить();
		НоваяСтрока.Номенклатура = Номенклатура;
	КонецЦикла;

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ РАЗЛИЧНЫЕ
	|	СписокНоменклатуры.Номенклатура КАК Номенклатура,
	|	ЕСТЬNULL(Товары.ВНаличииОстаток, 0) - ЕСТЬNULL(Резервы.ЗарезервированоОстаток, 0) КАК Свободно
	|ИЗ
	|	&СписокНоменклатуры КАК СписокНоменклатуры
	|		ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.ТоварыНаСкладах.Остатки(
	|				,
	|				Склад = &Склад
	|					И Номенклатура В (&МассивНоменклатуры)) КАК Товары
	|		ПО СписокНоменклатуры.Номенклатура = Товары.Номенклатура
	|		ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.Резервы.Остатки(
	|				,
	|				Склад = &Склад
	|					И Номенклатура В (&МассивНоменклатуры)) КАК Резервы
	|		ПО СписокНоменклатуры.Номенклатура = Резервы.Номенклатура";

	Запрос.УстановитьПараметр("СписокНоменклатуры", СписокНоменклатуры);
	Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
	Запрос.УстановитьПараметр("Склад", Склад);

	Возврат Запрос.Выполнить().Выгрузить();

