Функция РассчитатьСвободныеОстатки(МассивНоменклатуры, Склад)

	// Подготовим массив значений для параметра запроса
	МассивПарам = Новый Массив;
	Если МассивНоменклатуры = Неопределено Тогда
		Возврат Новый ТаблицаЗначений;
	КонецЕсли;
	Если ТипЗнч(МассивНоменклатуры) = Тип("Массив") Тогда
		Для Каждого Эл Из МассивНоменклатуры Цикл
			Если Эл <> Неопределено И Эл <> Не(null) Тогда
				МассивПарам.Добавить(Эл);
			КонецЕсли;
		КонецЦикла;
	Иначе
		// Если передана единичная ссылка
		МассивПарам.Добавить(МассивНоменклатуры);
	КонецЕсли;

	Если МассивПарам.Количество() = 0 Тогда
		Возврат Новый ТаблицаЗначений;
	КонецЕсли;

	// Запрос остатка в наличии по складу и номенклатуре
	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
		Т.Номенклатура КАК Номенклатура,
		СУММА(Т.ВНаличии) КАК ВНаличии
	ИЗ
		РегистрНакопления.ТоварыНаСкладах.Остатки КАК Т
	ГДЕ
		Т.Склад = &Склад
		И Т.Номенклатура В (&Список)
	СГРУППИРОВАТЬ ПО
		Т.Номенклатура";
	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("Список", МассивПарам);
	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	Доступность = Новый Соответствие;
	Пока Выборка.Следующий() Цикл
		Доступность.Вставить(Выборка.Номенклатура, ЗначениеЗаполнено(Выборка.ВНаличии) ? Выборка.ВНаличии : 0);
	КонецЦикла;

	// Запрос резервов по складу и номенклатуре
	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
		Р.Номенклатура КАК Номенклатура,
		СУММА(Р.Зарезервировано) КАК Зарезервировано
	ИЗ
		РегистрНакопления.Резервы.Остатки КАК Р
	ГДЕ
		Р.Склад = &Склад
		И Р.Номенклатура В (&Список)
	СГРУППИРОВАТЬ ПО
		Р.Номенклатура";
	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("Список", МассивPарам); // опечатка? поправим ниже

	// Вставим правильный параметр (повторно, чтобы избежать опечатки)
	Запрос.УстановитьПараметр("Список", МассивПарам);
	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	Резервы = Новый Соответствие;
	Пока Выборка.Следующий() Цикл
		Резервы.Вставить(Выборка.Номенклатура, ЗначениеЗаполнено(Выборка.Зарезервировано) ? Выборка.Зарезервировано : 0);
	КонецЦикла;

	// Собираем результат
	ТаблицаРезультат = Новый ТаблицаЗначений;
	ТаблицаРезультат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	ТаблицаРезультат.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число"));

	Для Индекс = 0 По МассивПарам.Количество() - 1 Цикл
		Номен = МассивПарам[Индекс];
		Доступно = Доступность.СодержитКлюч(Номен) ? Доступность.Получить(Номен) : 0;
		Зар = Резервы.СодержитКлюч(Номен) ? Резервы.Получить(Номен) : 0;
		Свободно = Доступно - Зар;
		Стр = ТаблицаРезультат.Добавить();
		Стр.Номенклатура = Номен;
		Стр.Свободно = Свободно;
	КонецЦикла;

	Возврат ТаблицаРезультат;

