Функция РассчитатьСвободныйОстаток(НоменклатураМассив, Склад) Экспорт
    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    Результат.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число"));

    Для Каждого Номенклатура Из НоменклатураМассив Цикл
        ОстатокНаличие = РегистрНакопления.ТоварыНаСкладах.ПолучитьОстаток(Склад, Номенклатура);
        ВНаличии = 0;
        Если ОстатокНаличие <> Неопределено Тогда
            ВНаличии = ОстатокНаличие.ВНаличии;
        КонецЕсли;

        ОстатокРезерв = РегистрНакопления.Резервы.ПолучитьОстаток(Склад, Номенклатура);
        Зарезервировано = 0;
        Если ОстатокРезерв <> Неопределено Тогда
            Зарезервировано = ОстатокРезерв.Зарезервировано;
        КонецЕсли;

        Свободно = ВНаличии - Зарезервировано;

        НоваяСтрока = Результат.Добавить();
        НоваяСтрока.Номенклатура = Номенклатура;
        НоваяСтрока.Свободно = Свободно;
    КонецЦикла;

    Возврат Результат;
