Функция ПолучитьСуммарныйДолгКонтрагента(СсылкаНаКонтрагента)
	Долг = 0;
	Запрос = Справочники.Договоры.СоздатьЗапрос();
	Запрос.Текст = "ВЫБРАТЬ Договор, СУММА(Взаиморасчеты.Остаток) КАК Остаток
					ИЗ Справочник.Договоры КАК Договор
					ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.Взаиморасчеты КАК Взаиморасчеты
					ПО Договор.Ссылка = Взаиморасчеты.Договор
					ГДЕ Договор.Контрагент = &Контрагент
					СГРУППИРОВАТЬ ПО Договор";

	Запрос.Параметры.Вставить("Контрагент", СсылкаНаКонтрагента);
	РезультатЗапроса = Запрос.Выполнить();

	Если РезультатЗапроса.Пустой() Тогда
		Возврат 0;
	Иначе
