Функция ПолучитьСальдоСчета(Счёт) Экспорт

    Запрос = Новый Запрос;
    Запрос.Текст = "
        ВЫБРАТЬ
            Хозрасчетный.СчётДт,
            Хозрасчетный.СчётКт,
            Хозрасчетный.Сумма
        ИЗ
            РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
        ГДЕ
            Хозрасчетный.СчётДт В ИЕРАРХИИ (&Счёт)
            ИЛИ Хозрасчетный.СчётКт В ИЕРАРХИИ (&Счёт)
    ";
    Запрос.УстановитьПараметр("Счёт", Счёт);

    РезультатЗапроса = Запрос.Выполнить();
    Выборка = РезультатЗапроса.Выбрать();

    ОборотПоДебету = 0;
    ОборотПоКредиту = 0;

    Пока Выборка.Следующий() Цикл
        Если Выборка.СчётДт = Счёт ИЛИ Выборка.СчётДт.ВИерархии(Счёт) Тогда
            ОборотПоДебету = ОборотПоДебету + Выборка.Сумма;
        КонецЕсли;
        Если Выборка.СчётКт = Счёт ИЛИ Выборка.СчётКт.ВИерархии(Счёт) Тогда
            ОборотПоКредиту = ОборотПоКредиту + Выборка.Сумма;
        КонецЕсли;
    КонецЦикла;

    ВидСчёта = Счёт.Вид;

    Если ВидСчёта = Перечисления.ВидыСчетов.Пассивный Тогда
        Сальдо = ОборотПоКредиту - ОборотПоДебету;
    Иначе
        Сальдо = ОборотПоДебету - ОборотПоКредиту;
    КонецЕсли;

    Возврат Сальдо;

КонецФункции
```

