    Выборка.Следующий();
    ОборотДт = Выборка.ОборотДт;

    Запрос2 = Новый Запрос;
    Запрос2.Текст = "ВЫБРАТЬ ЕСТЬNULL(СУММА(Хозрасчетный.Сумма), 0) КАК ОборотКт
                    |ИЗ РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
