Функция ПолучитьСальдоСчета(СсылкаНаСчет) Экспорт

    // Получаем вид счёта
    ВидСчета = СсылкаНаСчет.Вид;

    // Запрос для получения оборотов по счёту и всем его субсчетам
    Запрос = Новый Запрос;
    Запрос.Текст = 
        "ВЫБРАТЬ
        |    СУММА(ВЫБОР
        |        КОГДА ХозрасчетныйОбороты.СчетДт В ИЕРАРХИИ (&Счет)
        |            ТОГДА ХозрасчетныйОбороты.СуммаОборот
        |        ИНАЧЕ 0
        |    КОНЕЦ) КАК ОборотДт,
        |    СУММА(ВЫБОР
        |        КОГДА ХозрасчетныйОбороты.СчетКт В ИЕРАРХИИ (&Счет)
        |            ТОГДА ХозрасчетныйОбороты.СуммаОборот
        |        ИНАЧЕ 0
        |    КОНЕЦ) КАК ОборотКт
        |ИЗ
        |    РегистрБухгалтерии.Хозрасчетный.Обороты(, , , , , , , ) КАК ХозрасчетныйОбороты
        |ГДЕ
        |    ХозрасчетныйОбороты.СчетДт В ИЕРАРХИИ (&Счет)
        |    ИЛИ ХозрасчетныйОбороты.СчетКт В ИЕРАРХИИ (&Счет)";

    Запрос.УстановитьПараметр("Счет", СсылкаНаСчет);

    РезультатЗапроса = Запрос.Выполнить();

    Если РезультатЗапроса.Пустой() Тогда
        Возврат 0;
    КонецЕсли;

    Выборка = РезультатЗапроса.Выбрать();
    Выборка.Следующий();

    ОборотДт = ?(Выборка.ОборотДт = NULL, 0, Выборка.ОборотДт);
    ОборотКт = ?(Выборка.ОборотКт = NULL, 0, Выборка.ОборотКт);

    // Для пассивного счёта возвращаем кредитовое сальдо (Кт - Дт)
    // Для активного и активно-пассивного — дебетовое (Дт - Кт)
    Если ВидСчета = ВидСчета.Пассивный Тогда
        Возврат ОборотКт - ОборотДт;
    Иначе
        Возврат ОборотДт - ОборотКт;
    КонецЕсли;

КонецФункции
```

