Функция ПолучитьСальдоСчета(Счет) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	СУММА(ЕСТЬNULL(Дебет.Сумма, 0)) КАК ОборотДт,
	|	СУММА(ЕСТЬNULL(Кредит.Сумма, 0)) КАК ОборотКт
	|ИЗ
	|	(ВЫБРАТЬ
	|		Хозрасчетный.Сумма КАК Сумма
	|	ИЗ
	|		РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
	|	ГДЕ
	|		Хозрасчетный.СчетДт В ИЕРАРХИИ (&Счет)) КАК Дебет,
	|
	|	(ВЫБРАТЬ
	|		Хозрасчетный.Сумма КАК Сумма
	|	ИЗ
	|		РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
	|	ГДЕ
	|		Хозрасчетный.СчетКт В ИЕРАРХИИ (&Счет)) КАК Кредит";

	Запрос.УстановитьПараметр("Счет", Счет);

	Выборка = Запрос.Выбрать();

	ОборотДт = 0;
	ОборотКт = 0;
	Если Выборка.Следующий() Тогда
		ОборотДт = Выборка.ОборотДт;
		ОборотКт = Выборка.ОборотКт;
	КонецЕсли;

	Если Счет.Вид = ВидСчета.Пассивный Тогда
		Сальдо = ОборотКт - ОборотДт;
	Иначе
		Сальдо = ОборотДт - ОборотКт;
	КонецЕсли;

	Возврат Сальдо;

