Функция ПолучитьОстаткиТоваровНаСкладе(МассивНоменклатуры, Склад, ГруппаНоменклатуры = Неопределено) Экспорт

    ТаблицаОстатков = Новый ТаблицаЗначений;
    ТаблицаОстатков.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    ТаблицаОстатков.Колонки.Добавить("Остаток", Новый ОписаниеТипов("Число", , , Новый КвалификаторыЧисла(15, 3)));

    // Определяем режим работы
    ИспользоватьМассив = МассивНоменклатуры <> Неопределено И МассивНоменклатуры.Количество() > 0;
    ИспользоватьГруппу = ГруппаНоменклатуры <> Неопределено И ЗначениеЗаполнено(ГруппаНоменклатуры);

    // Если ни массив не задан, ни группа — возвращаем пустую таблицу
    Если НЕ ИспользоватьМассив И НЕ ИспользоватьГруппу Тогда
        Возврат ТаблицаОстатков;
    КонецЕсли;

    // Если склад не задан — возвращаем пустую таблицу
    Если Склад = Неопределено ИЛИ НЕ ЗначениеЗаполнено(Склад) Тогда
        Возврат ТаблицаОстатков;
    КонецЕсли;

    Запрос = Новый Запрос;

    Если ИспользоватьМассив Тогда
        // Режим 1: фильтрация по переданному массиву номенклатуры
        // Дополнительно можно уточнить группой, если она задана

        ТекстЗапроса = 
        "ВЫБРАТЬ
        |    Остатки.Номенклатура КАК Номенклатура,
        |    Остатки.ВНаличииОстаток КАК Остаток
        |ИЗ
        |    РегистрНакопления.ТоварыНаСкладах.Остатки(
        |        ,
        |        Склад = &Склад
        |            И Номенклатура В (&МассивНоменклатуры)";

        Если ИспользоватьГруппу Тогда
            ТекстЗапроса = ТекстЗапроса + "
        |            И Номенклатура В ИЕРАРХИИ (&ГруппаНоменклатуры)";
            Запрос.УстановитьПараметр("ГруппаНоменклатуры", ГруппаНоменклатуры);
        КонецЕсли;

        ТекстЗапроса = ТекстЗапроса + "
        |    ) КАК Остатки
        |ГДЕ
        |    Остатки.ВНаличииОстаток > 0";

        Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);

    Иначе
        // Режим 2: массив пуст, фильтрация только по группе номенклатуры

        ТекстЗапроса = 
        "ВЫБРАТЬ
        |    Остатки.Номенклатура КАК Номенклатура,
        |    Остатки.ВНаличииОстаток КАК Остаток
        |ИЗ
        |    РегистрНакопления.ТоварыНаСкладах.Остатки(
        |        ,
        |        Склад = &Склад
        |            И Номенклатура В ИЕРАРХИИ (&ГруппаНоменклатуры)
        |    ) КАК Остатки
        |ГДЕ
        |    Остатки.ВНаличииОстаток > 0";

        Запрос.УстановитьПараметр("ГруппаНоменклатуры", ГруппаНоменклатуры);

    КонецЕсли;

    Запрос.Текст = ТекстЗапроса;
    Запрос.УстановитьПараметр("Склад", Склад);

    РезультатЗапроса = Запрос.Выполнить();

    Если РезультатЗапроса.Пустой() Тогда
        Возврат ТаблицаОстатков;
    КонецЕсли;

    Выборка = РезультатЗапроса.Выбрать();
    Пока Выборка.Следующий() Цикл
        НоваяСтрока = ТаблицаОстатков.Добавить();
        НоваяСтрока.Номенклатура = Выборка.Номенклатура;
        НоваяСтрока.Остаток      = Выборка.Остаток;
    КонецЦикла;

    Возврат ТаблицаОстатков;

