Функция ПолучитьОстаткиНоменклатуры(МассивНоменклатуры, Склад, ГруппаНоменклатуры = Неопределено)
	ТаблицаОстатков = Новый ТаблицаЗначений;
	ТаблицаОстатков.Колонки.Добавить("Номенклатура", Тип("СправочникСсылка.Номенклатура"));
	ТаблицаОстатков.Колонки.Добавить("Остаток", Тип("Число"));

	Запрос = Новый Запрос;
	ЗапросТекст = "ВЫБРАТЬ 
					Номенклатура.Ссылка,
					OстаткиНаСкладахОстатки.Остаток
				ИЗ 
					РегистрНакопления.ОстаткиНаСкладах.Остатки(&ДатаНачала, , , , ) КАК ОстаткиНаСкладахОстатки
					ВОИНДЕКСЕ
					Справочник.Номенклатура КАК Номенклатура
				GДЕ 
				(OстаткиНаСкладахОстатки.Склад = &Склад)";

	// Если передана конкретная группа номенклатуры
	Если ГруппаНоменклатуры <> Неопределено Тогда
		ЗапросТекст += "
			И Номенклатура.Родитель = &ГруппаНоменклатуры
			ИЛИ Номенклатура в (&ВсеПодгруппы)";
		KонецЕсли;

	// Фильтрация по конкретной номенклатуре
	Если МассивНоменклатуры Неопределено Или МассивНоменклатуры.Количество() > 0 Тогда
		ЗапросТекст += "
			И Номенклатура в (&МассивНоменклатуры)";
	КонецЕсли;

	Запрос.Текст = ЗапросТекст;

	// Настройка параметров запроса
	Запрос.УстановитьПараметр("ДатаНачала", Дата(Сегодня()));
	Запрос.УстановитьПараметр("Склад", Склад);
	Если ГруппаНоменклатуры <> Неопределено Тогда
		Запрос.УстановитьПараметр("ГруппаНоменклатуры", ГруппаНоменклатуры);
		Запрос.УстановитьПараметр("ВсеПодгруппы", ГруппаНоменклатуры.Поломка());
	КонецЕсли;
	Если МассивНоменклатуры Неопределено Тогда
		MассивНоменклатуры = [];
	КонецЕсли;
	Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);

	РезультатЗапроса = Запрос.ВыполнитьПакет();
	Если РезультатЗапроса.Пустой() Тогда
		Возврат ТаблицаОстатков;
	КонецЕсли;

	ВыборкаДетальныеДанные = РезультатЗапроса.Выбрать();
	Пока ВыборкаДетальныеДанные.Следующий() Цикл
		НоваяСтрока = ТаблицаОстатков.Добавить();
		НоваяСтрока.Номенклатура = ВыборкаДетальныеДанные.Ссылка;
		НоваяСтрока.Остаток = ВыборкаДетальныеДанные.Остаток;
	КонецЦикла;

	Возврат ТаблицаОстатков;
КонецФункции

 function получитьОстаткиНоменклатуры(массивНоменклатуры, группаНоменклатуры) Экспорт
    если не массивНоменклатуры или не значениемассивНоменклатуры тогда
        массивНоменклатуры = Справочники.Номенклатура.ПолучитьГруппуНоменклатуры(группаНоменклатуры);
