    ТаблицаОстатов.Колонки.Добавить("Остаток");

    Для каждого элемент из массивНоменклатуры Цикл
        СтруктураЗапроса = Новый Структура;
        СтруктураЗапроса.Вставить("Склад", ПереданныйСклад);

        Запрос = новый Запрос;
        Запрос.Текст = "ВЫБРАТЬ |   РегистрНакопления.ОстаткиНАСкладе.Остаток КАК Остаток, |
