Функция ПолучитьОстаткиТоваровНаСкладе(МассивНоменклатуры, Склад, ГруппаНоменклатуры = Неопределено) Экспорт

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура");
	Результат.Колонки.Добавить("Остаток");

	Если Не ЗначениеЗаполнено(Склад) Тогда
		Возврат Результат;
	КонецЕсли;

	ЕстьМассивНоменклатуры = Ложь;
	Если МассивНоменклатуры <> Неопределено Тогда
		Если ТипЗнч(МассивНоменклатуры) = Тип("Массив") Тогда
			ЕстьМассивНоменклатуры = МассивНоменклатуры.Количество() > 0;
		КонецЕсли;
	КонецЕсли;

	ЕстьГруппаНоменклатуры = ЗначениеЗаполнено(ГруппаНоменклатуры);

	ТекстЗапроса =
	"ВЫБРАТЬ
	|	ТоварыНаСкладахОстатки.Номенклатура КАК Номенклатура,
	|	ТоварыНаСкладахОстатки.ВНаличииОстаток КАК Остаток
	|ИЗ
	|	РегистрНакопления.ТоварыНаСкладах.Остатки(, Склад = &Склад) КАК ТоварыНаСкладахОстатки";

	Условия = Новый Массив;

	Если ЕстьМассивНоменклатуры Тогда
		Условия.Добавить("ТоварыНаСкладахОстатки.Номенклатура В (&МассивНоменклатуры)");
	КонецЕсли;

	Если ЕстьГруппаНоменклатуры Тогда
		Условия.Добавить("ТоварыНаСкладахОстатки.Номенклатура В ИЕРАРХИИ (&ГруппаНоменклатуры)");
	КонецЕсли;

	Если Условия.Количество() > 0 Тогда
		ТекстЗапроса = ТекстЗапроса + Символы.ПС + "|ГДЕ" + Символы.ПС;
		Для Индекс = 0 По Условия.Количество() - 1 Цикл
			Если Индекс > 0 Тогда
				ТекстЗапроса = ТекстЗапроса + Символы.ПС + "|	И ";
			Иначе
				ТекстЗапроса = ТекстЗапроса + "|	";
			КонецЕсли;
			ТекстЗапроса = ТекстЗапроса + Условия[Индекс];
		КонецЦикла;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст = ТекстЗапроса;
	Запрос.УстановитьПараметр("Склад", Склад);

	Если ЕстьМассивНоменклатуры Тогда
		Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
	КонецЕсли;

	Если ЕстьГруппаНоменклатуры Тогда
		Запрос.УстановитьПараметр("ГруппаНоменклатуры", ГруппаНоменклатуры);
	КонецЕсли;

	Возврат Запрос.Выполнить().Выгрузить();

КонецФункции

Функция ПолучитьОстаткиТоваров(МассивНоменклатуры, Склад, ГруппаНоменклатуры)
	ТабРезультат = Новый ТаблицаЗначений;
	ТабРезультат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	ТабРезультат.Колонки.Добавить("Остаток", Новый ОписаниеТипов("Число"));

	Если Склад = Неопределено Тогда
		Возврат ТабРезультат;
	КонецЕсли;

	Если МассивНоменклатуры = Неопределено Тогда
		МассивНоменклатуры = Новый Массив;
	КонецЕсли;

	// Если не задан ни массив, ни группа — возвращаем пустую таблицу
	Если МассивНоменклатуры.Количество() = 0 И ГруппаНоменклатуры = Неопределено Тогда
		Возврат ТабРезультат;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст =
		"ВЫБРАТЬ
			ТоварыНаСкладах.Номенклатура КАК Номенклатура,
			СУММА(ТоварыНаСкладах.ВНаличии) КАК Остаток
		ИЗ
			РегистрНакопления.ТоварыНаСкладах КАК ТоварыНаСкладах
		ГДЕ
			ТоварыНаСкладах.Склад = &Склад
		СГРУППИРОВАТЬ ПО
			ТоварыНаСкладах.Номенклатура";
	Запрос.УстановитьПараметр("Склад", Склад);

	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	Пока Выборка.Следующий() Цикл
		НоменклатураСсылка = Выборка.Номенклатура;
		Остаток = Выборка.Остаток;

		// фильтрация по массиву, если он не пуст
		Если МассивНоменклатуры.Количество() > 0 Тогда
			ЕстьВМассиве = Ложь;
			Для Каждого Элемент Из МассивНоменклатуры Цикл
				Если Элемент = НоменклатураСсылка Тогда
					ЕстьВМассиве = Истина;
					Прервать;
				КонецЕсли;
			КонецЦикла;
			Если Не ЕстьВМассиве Тогда
				Продолжить;
			КонецЕсли;
		КонецЕсли;

		// фильтрация по группе, если задана
		Если ГруппаНоменклатуры <> Неопределено Тогда
			Если Не ПринадлежитКГруппе(НоменклатураСсылка, ГруппаНоменклатуры) Тогда
				Продолжить;
			КонецЕсли;
		КонецЕсли;

		НоваяСтрока = ТабРезультат.Добавить();
		НоваяСтрока.Номенклатура = НоменклатураСсылка;
		НоваяСтрока.Остаток = Остаток;
	КонецЦикла;

	Возврат ТабРезультат;
КонецФункции

Функция ПринадлежитКГруппе(НоменклатураСсылка, ГруппаСсылка)
	Если НоменклатураСсылка = Неопределено Или ГруппаСсылка = Неопределено Тогда
		Возврат Ложь;
	КонецЕсли;

	Текущий = НоменклатураСсылка;
	Пока Текущий <> Неопределено Цикл
		Если Текущий = ГруппаСсылка Тогда
			Возврат Истина;
		КонецЕсли;
		Попытка
			Текущий = Текущий.Родитель;
		Исключение
			Текущий = Неопределено;
		КонецПопытки;
	КонецЦикла;

	Возврат Ложь;
КонецФункции

