Функция ПолучитьОстаткиТоваровНаСкладе(МассивНоменклатуры, Склад, ГруппаНоменклатуры = Неопределено) Экспорт

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура");
	Результат.Колонки.Добавить("Остаток");

	ЕстьНоменклатура = Ложь;
	Если МассивНоменклатуры <> Неопределено Тогда
		ЕстьНоменклатура = МассивНоменклатуры.Количество() > 0;
	КонецЕсли;

	Если НЕ ЕстьНоменклатура И НЕ ЗначениеЗаполнено(ГруппаНоменклатуры) Тогда
		Возврат Результат;
	КонецЕсли;

	ТекстЗапроса =
	"ВЫБРАТЬ
	|	Остатки.Номенклатура КАК Номенклатура,
	|	Остатки.ВНаличииОстаток КАК Остаток
	|ИЗ
	|	РегистрНакопления.ТоварыНаСкладах.Остатки(, Склад = &Склад) КАК Остатки";

	Условия = Новый Массив;

	Если ЕстьНоменклатура Тогда
		Условия.Добавить("Остатки.Номенклатура В (&МассивНоменклатуры)");
	КонецЕсли;

	Если ЗначениеЗаполнено(ГруппаНоменклатуры) Тогда
		Условия.Добавить("Остатки.Номенклатура В ИЕРАРХИИ (&ГруппаНоменклатуры)");
