	Если Условия.Количество() > 0 Тогда
		ТекстЗапроса = ТекстЗапроса + Символы.ПС + "|ГДЕ";

		Для НомерУсловия = 0 По Условия.Количество() - 1 Цикл
			Если НомерУсловия > 0 Тогда
				ТекстЗапроса = ТекстЗапроса + Символы.ПС + "|	И ";
			Иначе
				ТекстЗапроса = ТекстЗапроса + Символы.ПС + "|	";
			КонецЕсли;

			ТекстЗапроса = ТекстЗапроса + Условия[НомерУсловия];
		КонецЦикла;
	КонецЕсли;

	Запрос = Новый Запрос(ТекстЗапроса);
	Запрос.УстановитьПараметр("Склад", Склад);

	Если ЕстьНоменклатура Тогда
		Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
	КонецЕсли;

	Если ЗначениеЗаполнено(ГруппаНоменклатуры) Тогда
		Запрос.УстановитьПараметр("ГруппаНоменклатуры", ГруппаНоменклатуры);
	КонецЕсли;

	Возврат Запрос.Выполнить().Выгрузить();

