	|	ТоварыНаСкладахОстатки.Номенклатура.Наименование";

	МассивНоменклатурыПуст = (МассивНоменклатуры = Неопределено) ИЛИ (ТипЗнч(МассивНоменклатуры) <> Тип("Массив")) ИЛИ (МассивНоменклатуры.Количество() = 0);
	ГруппаЗадана = (ГруппаНоменклатуры <> Неопределено) И (ЗначениеЗаполнено(ГруппаНоменклатуры));

	Если НЕ МассивНоменклатурыПуст Тогда

		Запрос.УстановитьПараметр("Номенклатура", МассивНоменклатуры);
		ТекстЗапроса = СтрЗаменить(ТекстЗапроса, "&УсловиеНоменклатура", "Номенклатура В (&Номенклатура)");

	ИначеЕсли ГруппаЗадана Тогда

		Запрос.УстановитьПараметр("ГруппаНоменклатуры", ГруппаНоменклатуры);
		ТекстЗапроса = СтрЗаменить(ТекстЗапроса, "&УсловиеНоменклатура", "Номенклатура В ИЕРАРХИИ (&ГруппаНоменклатуры)");

	Иначе

		ТекстЗапроса = СтрЗаменить(ТекстЗапроса, "И &УсловиеНоменклатура", "");

	КонецЕсли;

	Запрос.Текст = ТекстЗапроса;

	РезультатЗапроса = Запрос.Выполнить();
	ТаблицаОстатков = РезультатЗапроса.Выгрузить();

	Возврат ТаблицаОстатков;

