Функция ПолучитьДебетовыйОборотПоКонтрагенту(СчетДт, Контрагент) Экспорт

    // Определяем позицию субконто "Контрагенты" на переданном счёте
    НомерСубконто = 0;

    СчетОбъект = СчетДт.ПолучитьОбъект();
    Если СчетОбъект = Неопределено Тогда
        Возврат 0;
    КонецЕсли;

    ВидыСубконтоСчета = СчетОбъект.ВидыСубконто;

    Для Каждого СтрокаВидСубконто Из ВидыСубконтоСчета Цикл
        // Проверяем, является ли данный вид субконто видом для контрагентов
        ТипЗначения = СтрокаВидСубконто.ВидСубконто.ТипЗначения;
        Если ТипЗначения.СодержитТип(Тип("СправочникСсылка.Контрагенты")) Тогда
            НомерСубконто = СтрокаВидСубконто.НомерСубконто;
            Прервать;
        КонецЕсли;
    КонецЦикла;

    Если НомерСубконто = 0 Тогда
        // На данном счёте нет субконто типа "Контрагенты"
        Возврат 0;
    КонецЕсли;

    // Формируем запрос к виртуальной таблице ДвиженияССубконто
    // Фильтруем по нужному субконто дебета в зависимости от его позиции

    ИмяПоляСубконто = "СубконтоДт" + Формат(НомерСубконто, "ЧГ=0");

    ТекстЗапроса = 
    "ВЫБРАТЬ
    |    СУММА(Движения.Сумма) КАК ОборотДт
    |ИЗ
    |    РегистрБухгалтерии.Хозрасчетный.ДвиженияССубконто(
    |        ,
    |        ,
    |        СчетДт = &СчетДт,
    |        ,
    |    ) КАК Движения
    |ГДЕ
    |    Движения.СчетДт = &СчетДт
    |    И Движения." + ИмяПоляСубконто + " = &Контрагент";

    Запрос = Новый Запрос;
    Запрос.Текст = ТекстЗапроса;
    Запрос.УстановитьПараметр("СчетДт", СчетДт);
    Запрос.УстановитьПараметр("Контрагент", Контрагент);

    РезультатЗапроса = Запрос.Выполнить();

    Если РезультатЗапроса.Пустой() Тогда
        Возврат 0;
    КонецЕсли;

    Выборка = РезультатЗапроса.Выбрать();
    Выборка.Следующий();

    ОборотДт = Выборка.ОборотДт;

    Если ОборотДт = Неопределено Тогда
        Возврат 0;
    КонецЕсли;

    Возврат ОборотДт;

КонецФункции
