Процедура ЗаполнитьЦеныВТоварах(Товары, ВидЦен, Дата) Экспорт

	НоменклатураДляОтбора = Новый Массив;

	Для Каждого СтрокаТоваров Из Товары Цикл
		СтрокаТоваров.Цена = 0;
		СтрокаТоваров.Сумма = 0;

		Если ЗначениеЗаполнено(СтрокаТоваров.Номенклатура) Тогда
			НоменклатураДляОтбора.Добавить(СтрокаТоваров.Номенклатура);
		КонецЕсли;
	КонецЦикла;

	Если НоменклатураДляОтбора.Количество() = 0 Или Не ЗначениеЗаполнено(ВидЦен) Тогда
		Возврат;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	Цены.Номенклатура КАК Номенклатура,
	|	Цены.Цена КАК Цена
	|ИЗ
	|	РегистрСведений.ЦеныНоменклатуры.СрезПоследних(
	|		&Дата,
	|		ВидЦен = &ВидЦен
	|			И Номенклатура В (&НоменклатураДляОтбора)) КАК Цены";

	Запрос.УстановитьПараметр("Дата", Дата);
	Запрос.УстановитьПараметр("ВидЦен", ВидЦен);
	Запрос.УстановитьПараметр("НоменклатураДляОтбора", НоменклатураДляОтбора);

	ЦеныНоменклатуры = Новый Соответствие;

	Выборка = Запрос.Выполнить().Выбрать();
	Пока Выборка.Следующий() Цикл
		ЦеныНоменклатуры.Вставить(Выборка.Номенклатура, Выборка.Цена);
	КонецЦикла;

	Для Каждого СтрокаТоваров Из Товары Цикл
		Цена = ЦеныНоменклатуры.Получить(СтрокаТоваров.Номенклатура);

		Если Цена <> Неопределено Тогда
			СтрокаТоваров.Цена = Цена;
			СтрокаТоваров.Сумма = СтрокаТоваров.Количество * СтрокаТоваров.Цена;
		КонецЕсли;
	КонецЦикла;

КонецПроцедуры

Процедура ЗаполнитьЦены(ТоварыТЧ, ВидЦен, Дата)
	// Проверка входных данных
	Если ТоварыТЧ = Неопределено Тогда
		Возврат;
	КонецЕсли;

	// Собираем уникальные номенклатуры из табличной части
	СписокНоменклатур = Новый СписокЗначений;
	Для Каждого Строка Из ТоварыТЧ Цикл
		Если Строка.Номенклатура <> Неопределено Тогда
			Если НЕ СписокНоменклатур.Найти(Строка.Номенклатура) Тогда
				СписокНоменклатур.Добавить(Строка.Номенклатура);
			КонецЕсли;
		КонецЕсли;
	КонецЦикла;
	Если СписокНоменклатур.Количество() = 0 Тогда
		// Нет позиций — ничего не делаем
		Возврат;
	КонецЕсли;

	// Запрос с использованием среза последних значений регистра
	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
		Цены.Номенклатура КАК Номенклатура,
		Цены.Цена КАК Цена
	ИЗ
		РегистрСведений.ЦеныНоменклатуры.СрезПоследних(&Дата, Номенклатура, ВидЦен) КАК Цены
	ГДЕ
		Цены.ВидЦен = &ВидЦен
		И Цены.Номенклатура В(&СписокНоменклатур)";

	Запрос.УстановитьПараметр("Дата", Дата);
	Запрос.УстановитьПараметр("ВидЦен", ВидЦен);
	Запрос.УстановитьПараметр("СписокНоменклатур", СписокНоменклатур);

	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	// Соответствие номенклатура -> цена
	ЦеныСоответствие = Новый Соответствие;
	Пока Выборка.Следующий() Цикл
		Если НЕ ЦеныСоответствие.СодержитКлюч(Выборка.Номенклатура) Тогда
			ЦеныСоответствие.Вставить(Выборка.Номенклатура, Выборка.Цена);
		КонецЕсли;
	КонецЦикла;

	// Заполняем цены и пересчитываем суммы в табличной части
	Для Каждого Строка Из ТоварыТЧ Цикл
		Если Строка.Номенклатура <> Неопределено И ЦеныСоответствие.СодержитКлюч(Строка.Номенклатура) Тогда
			Строка.Цена = ЦеныСоответствие.Получить(Строка.Номенклатура);
		Иначе
			Строка.Цена = 0;
		КонецЕсли;
		Строка.Сумма = ЗначениеЗаполнено(Строка.Количество) И ЗначениеЗаполнено(Строка.Цена)
			? Строка.Количество * Строка.Цена
			: 0;
	КонецЦикла;
КонецПроцедуры

