                ПартииТоваровНаСкладах.Партия КАК Партия,
                ПартииТоваровНаСкладах.Количество КАК КоличествоОстатка,
                ПартииТоваровНаСкладах.Стоимость КАК СтоимостьОстатка
            ИЗ
                РегистрНакопления.ПартииТоваровНаСкладах.Остатки(, Склад = &Склад И Номенклатура = &Номенклатура) КАК ПартииТоваровНаСкладах
            УПОРЯДОЧИТЬ ПО
                ПартииТоваровНаСкладах.Партия.Дата ВОЗР
        ";
        Запрос.УстановитьПараметр("Склад", Склад);
        Запрос.УстановитьПараметр("Номенклатура", Номенклатура);
        РезультатЗапроса = Запрос.Выполнить();
        Выборка = РезультатЗапроса.Выбрать();

        Пока Выборка.Следующий() Цикл
            Если СписанноеКоличество >= ТребуемоеКоличество Тогда
                Прервать;
            КонецЕсли;

            ДоступноеКоличество = Выборка.КоличествоОстатка;
            СтоимостьПартии = Выборка.СтоимостьОстатка;
            ЦенаЗаЕдиницу = ДоступноеКоличество > 0 ? СтоимостьПартии / ДоступноеКоличество : 0;

            КоличествоКСписаниюИзПартии = Мин(ДоступноеКоличество, ТребуемоеКоличество - СписанноеКоличество);

            НоваяСтрока = Результат.Добавить();
            НоваяСтрока.Номенклатура = Номенклатура;
            НоваяСтрока.Партия = Выборка.Партия;
            НоваяСтрока.Количество = КоличествоКСписаниюИзПартии;
            НоваяСтрока.Стоимость = КоличествоКСписаниюИзПартии * ЦенаЗаЕдиницу;

            СписанноеКоличество = СписанноеКоличество + КоличествоКСписаниюИзПартии;
        КонецЦикла;

        Если СписанноеКоличество < ТребуемоеКоличество Тогда
            ВызватьИсключение "Недостаточно остатков для номенклатуры: " + Номенклатура.Наименование;
        КонецЕсли;

    КонецЦикла;

    Возврат Результат;

