Функция СписатьТоварыFIFO(ТаблицаТоваровКсписанию, Склад)

    ТаблицаРезультата = Новый ТаблицаЗначений;
    ТаблицаРезультата.Колонки.Добавить("Номенклатура");
    ТаблицаРезультата.Колонки.Добавить("Партия");
    ТаблицаРезультата.Колонки.Добавить("Количество");
    ТаблицаРезультата.Колонки.Добавить("Стоимость");

    Для Каждого СтрокаТовараКсписанию Из ТаблицаТоваровКсписанию Цикл

        Номенклатура = СтрокаТовараКсписанию.Номенклатура;
        КоличествоКсписанию = СтрокаТовараКсписанию.Количество;

        ОстаткиПоНоменклатуре = ПолучитьОстаткиПоНоменклатуре(Номенклатура, Склад);

        Если ОстаткиПоНоменклатуре.Количество() = 0 Тогда
            ВызватьИсключение СтроковыеФункцииКлиентСервер.ПодставитьПараметрыВСтроку(
                "Недостаточно остатков по номенклатуре ""%1"".",
                Номенклатура
            );
        КонецЕсли;

        Для Каждого СтрокаОстатка Из ОстаткиПоНоменклатуре Цикл
            Если КоличествоКсписанию <= 0 Тогда
                Прервать;
            КонецЕсли;

            КоличествоСписываемоеИзПартии = Минимальное(КоличествоКсписанию, СтрокаОстатка.Количество);

            Если КоличествоСписываемоеИзПартии > 0 Тогда
                НоваяСтрокаРезультата = ТаблицаРезультата.Добавить();
                НоваяСтрокаРезультата.Номенклатура = Номенклатура;
                НоваяСтрокаРезультата.Партия = СтрокаОстатка.Партия;
                НоваяСтрокаРезультата.Количество = КоличествоСписываемоеИзПартии;
                НоваяСтрокаРезультата.Стоимость = КоличествоСписываемоеИзПартии * СтрокаОстатка.Цена;

                КоличествоКсписанию = КоличествоКсписанию - КоличествоСписываемоеИзПартии;
            КонецЕсли;

        КонецЦикла;

        Если КоличествоКсписанию > 0 Тогда
            ВызватьИсключение СтроковыеФункцииКлиентСервер.ПодставитьПараметрыВСтроку(
                "Недостаточно остатков по номенклатуре ""%1"".",
                Номенклатура
            );
        КонецЕсли;

    КонецЦикла;

    Возврат ТаблицаРезультата;

