			КонецЕсли;

			// Цена единицы из партии
			Цена = 0;
			Если ОстатокПартии > 0 Тогда
				Цена = ОстатокСтоимости / ОстатокПартии;
			КонецЕсли;

			// Стоимость списания
			СтоимостьСписания = Цена * Списать;

			// Добавляем строку в результат
			НоваяСтрока = Результат.Добавить();
			НоваяСтрока.Номенклатура = Номенклатура;
			НоваяСтрока.Партия = Партия;
