Функция СписатьТоварыФИФО(ТаблицаТоваров, Склад) Экспорт

    // Собираем список номенклатуры для запроса
    СписокНоменклатуры = Новый СписокЗначений;
    Для Каждого СтрокаТовара Из ТаблицаТоваров Цикл
        СписокНоменклатуры.Добавить(СтрокаТовара.Номенклатура);
    КонецЦикла;

    // Получаем остатки по партиям с сортировкой по дате партии (FIFO)
    Запрос = Новый Запрос;
    Запрос.Текст = 
        "ВЫБРАТЬ
        |    ПартииТоваровНаСкладахОстатки.Номенклатура КАК Номенклатура,
        |    ПартииТоваровНаСкладахОстатки.Партия КАК Партия,
        |    ПартииТоваровНаСкладахОстатки.КоличествоОстаток КАК КоличествоОстаток,
        |    ПартииТоваровНаСкладахОстатки.СтоимостьОстаток КАК СтоимостьОстаток
        |ИЗ
        |    РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
        |        ,
        |        Склад = &Склад
        |            И Номенклатура В (&СписокНоменклатуры)
        |    ) КАК ПартииТоваровНаСкладахОстатки
        |ГДЕ
        |    ПартииТоваровНаСкладахОстатки.КоличествоОстаток > 0
        |УПОРЯДОЧИТЬ ПО
        |    ПартииТоваровНаСкладахОстатки.Номенклатура,
        |    ПартииТоваровНаСкладахОстатки.Партия.Дата";

    Запрос.УстановитьПараметр("Склад", Склад);
    Запрос.УстановитьПараметр("СписокНоменклатуры", СписокНоменклатуры);

    РезультатЗапроса = Запрос.Выполнить();
    ВыборкаОстатков = РезультатЗапроса.Выбрать();

    // Строим структуру остатков по номенклатуре: Номенклатура -> массив строк партий
    ОстаткиПоНоменклатуре = Новый Соответствие;
    Пока ВыборкаОстатков.Следующий() Цикл
        НоменклатураКлюч = ВыборкаОстатков.Номенклатура;
        Если ОстаткиПоНоменклатуре[НоменклатураКлюч] = Неопределено Тогда
            ОстаткиПоНоменклатуре[НоменклатураКлюч] = Новый Массив;
        КонецЕсли;

        СтрокаПартии = Новый Структура;
        СтрокаПартии.Вставить("Партия",              ВыборкаОстатков.Партия);
        СтрокаПартии.Вставить("КоличествоОстаток",   ВыборкаОстатков.КоличествоОстаток);
        СтрокаПартии.Вставить("СтоимостьОстаток",    ВыборкаОстатков.СтоимостьОстаток);

        ОстаткиПоНоменклатуре[НоменклатураКлюч].Добавить(СтрокаПартии);
    КонецЦикла;

    // Результирующая таблица распределения
    ТаблицаРаспределения = Новый ТаблицаЗначений;
    ТаблицаРаспределения.Колонки.Добавить("Номенклатура");
    ТаблицаРаспределения.Колонки.Добавить("Партия");
    ТаблицаРаспределения.Колонки.Добавить("Количество", Новый ОписаниеТипов("Число", , , Новый КвалификаторыЧисла(15, 3)));
    ТаблицаРаспределения.Колонки.Добавить("Стоимость",  Новый ОписаниеТипов("Число", , , Новый КвалификаторыЧисла(15, 2)));

    // Обходим строки таблицы товаров к списанию
    Для Каждого СтрокаТовара Из ТаблицаТоваров Цикл

        Номенклатура        = СтрокаТовара.Номенклатура;
        КоличествоКСписанию = СтрокаТовара.Количество;

        МассивПартий = ОстаткиПоНоменклатуре[Номенклатура];

        // Проверяем наличие остатков вообще
        Если МассивПартий = Неопределено Тогда
            ВызватьИсключение "Недостаточно остатков для номенклатуры: " + Строка(Номенклатура);
        КонецЕсли;

        // Проверяем суммарный остаток
        СуммарныйОстаток = 0;
        Для Каждого СтрокаПартии Из МассивПартий Цикл
            СуммарныйОстаток = СуммарныйОстаток + СтрокаПартии.КоличествоОстаток;
        КонецЦикла;

        Если СуммарныйОстаток < КоличествоКСписанию Тогда
            ВызватьИсключение "Недостаточно остатков для номенклатуры: " + Строка(Номенклатура)
                + " (требуется: " + КоличествоКСписанию + ", доступно: " + СуммарныйОстаток + ")";
        КонецЕсли;

        // Списываем по партиям методом FIFO
        ОсталосьСписать = КоличествоКСписанию;

        Для Каждого СтрокаПартии Из МассивПартий Цикл

            Если ОсталосьСписать <= 0 Тогда
                Прервать;
            КонецЕсли;

            Если СтрокаПартии.КоличествоОстаток <= 0 Тогда
                Продолжить;
            КонецЕсли;

            // Определяем сколько списываем из текущей партии
            КоличествоИзПартии = Мин(ОсталосьСписать, СтрокаПартии.КоличествоОстаток);

            // Рассчитываем стоимость пропорционально количеству
            Если СтрокаПартии.КоличествоОстаток <> 0 Тогда
                ЦенаЗаЕдиницу = СтрокаПартии.СтоимостьОстаток / СтрокаПартии.КоличествоОстаток;
            Иначе
                ЦенаЗаЕдиницу = 0;
            КонецЕсли;

            СтоимостьСписания = Окр(КоличествоИзПартии * ЦенаЗаЕдиницу, 2);

            // Добавляем строку в результат
            НоваяСтрока = ТаблицаРаспределения.Добавить();
            НоваяСтрока.Номенклатура = Номенклатура;
            НоваяСтрока.Партия       = СтрокаПартии.Партия;
            НоваяСтрока.Количество   = КоличествоИзПартии;
            НоваяСтрока.Стоимость    = СтоимостьСписания;

            // Уменьшаем остаток партии и остаток к списанию
            СтрокаПартии.КоличествоОстаток = СтрокаПартии.КоличествоОстаток - КоличествоИзПартии;
            СтрокаПартии.СтоимостьОстаток  = СтрокаПартии.СтоимостьОстаток  - СтоимостьСписания;
            ОсталосьСписать = ОсталосьСписать - КоличествоИзПартии;

        КонецЦикла;

    КонецЦикла;

    Возврат ТаблицаРаспределения;

