	ТаблицаРаспределения.Колонки.Добавить("Стоимость");

	// Подготовка списка номенклатуры
	СписокНоменклатуры = ТоварыКСписанию.ВыгрузитьКолонку("Номенклатура");

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	Остатки.Номенклатура КАК Номенклатура,
	|	Остатки.Партия КАК Партия,
	|	Остатки.Партия.Дата КАК ДатаПартии,
	|	Остатки.КоличествоОстаток КАК Количество,
	|	Остатки.СтоимостьОстаток КАК Стоимость
	|ИЗ
	|	РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
	|		,
	|		Склад = &Склад
	|			И Номенклатура В (&СписокНоменклатуры)) КАК Остатки
	|ГДЕ
	|	Остатки.КоличествоОстаток > 0
	|
	|УПОРЯДОЧИТЬ ПО
	|	Остатки.Номенклатура,
	|	ДатаПартии";

	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("СписокНоменклатуры", СписокНоменклатуры);

	ТаблицаОстатков = Запрос.Выполнить().Выгрузить();

	// Группировка потребности по номенклатуре
	ПотребностьПоНоменклатуре = Новый Соответствие;
	Для Каждого СтрокаТовара Из ТоварыКСписанию Цикл
		ТекущаяПотребность = ПотребностьПоНоменклатуре.Получить(СтрокаТовара.Номенклатура);
		Если ТекущаяПотребность = Неопределено Тогда
			ТекущаяПотребность = 0;
		КонецЕсли;
		ПотребностьПоНоменклатуре.Вставить(СтрокаТовара.Номенклатура, ТекущаяПотребность + СтрокаТовара.Количество);
	КонецЦикла;

	Для Каждого ЭлементПотребности Из ПотребностьПоНоменклатуре Цикл

		Номенклатура = ЭлементПотребности.Ключ;
		ОсталосьСписать = ЭлементПотребности.Значение;

		Если ОсталосьСписать <= 0 Тогда
			Продолжить;
		КонецЕсли;

		СтрокиПартий = ТаблицаОстатков.НайтиСтроки(Новый Структура("Номенклатура", Номенклатура));

		Для Каждого СтрокаПартии Из СтрокиПартий Цикл

			Если ОсталосьСписать <= 0 Тогда
				Прервать;
			КонецЕсли;

			КоличествоИзПартии = Мин(ОсталосьСписать, СтрокаПартии.Количество);

			ЦенаПартии = ?(СтрокаПартии.Количество = 0, 0, СтрокаПартии.Стоимость / СтрокаПартии.Количество);
			СтоимостьСписания = ЦенаПартии * КоличествоИзПартии;

			НоваяСтрока = ТаблицаРаспределения.Добавить();
			НоваяСтрока.Номенклатура = Номенклатура;
			НоваяСтрока.Партия = СтрокаПартии.Партия;
			НоваяСтрока.Количество = КоличествоИзПартии;
			НоваяСтрока.Стоимость = СтоимостьСписания;

			ОсталосьСписать = ОсталосьСписать - КоличествоИзПартии;

		КонецЦикла;

		Если ОсталосьСписать > 0 Тогда
			ВызватьИсключение "Недостаточно остатков для списания номенклатуры: """
				+ Строка(Номенклатура) + """. Не хватает: " + Строка(ОсталосьСписать);
		КонецЕсли;

	КонецЦикла;

	Возврат ТаблицаРаспределения;

