    ТаблицаРаспределения = Новый ТаблицаЗначений;
    ТаблицаРаспределения.Колонки.Добавить("Номенклатура");
    ТаблицаРаспределения.Колонки.Добавить("Партия");
    ТаблицаРаспределения.Колонки.Добавить("Количество");
    ТаблицаРаспределения.Колонки.Добавить("Стоимость");

    // Получаем остатки товаров на складе
    Запрос = Новый Запрос;
    Запрос.Текст = "
    ВЫБРАТЬ
        ПартииТоваровНаСкладах.Номенклатура,
        ПартииТоваровНаСкладах.Партия,
        ПартииТоваровНаСкладах.Количество,
        ПартииТоваровНаСкладах.Стоимость
    ИЗ
        РегистрНакопления.ПартииТоваровНаСкладах КАК ПартииТоваровНаСкладах
    ГДЕ
        ПартииТоваровНаСкладах.Склад = &Склад
    УПОРЯДОЧИТЬ ПО
        ПартииТоваровНаСкладах.Партия.Дата ПО ВОЗРАСТАНИЮ";

    РезультатЗапроса = Запрос.Выполнить();
    ТаблицаОстатков = РезультатЗапроса.Выгрузить();

    // Проходим по каждой номенклатуре в таблице списания
    Для Каждого СтрокаТаблицыТоваровКСписанию Из ТаблицаТоваровКСписанию Цикл
        Номенклатура = СтрокаТаблицыТоваровКСписанию.Номенклатура;
        Количество = СтрокаТаблицыТоваровКСписанию.Количество;

        // Находим все партии данной номенклатуры на складе
        ПартииНоменклатуры = Новый Массив;
        Для Каждого СтрокаТаблицыОстатков Из ТаблицаОстатков Цикл
            Если СтрокаТаблицыОстатков.Номенклатура = Номенклатура Тогда
                ПартииНоменклатуры.Добавить(СтрокаТаблицыОстатков);
            КонецЕсли;
        КонецЦикла;

        // Списываем товары методом FIFO
        Для Индекс = 0 По ПартииНоменклатуры.ВГраница() Цикл
            Партия = ПартииНоменклатуры[Индекс].Партия;
            КоличествоВПартии = ПартииНоменклатуры[Индекс].Количество;

            // Проверяем, достаточно ли остатков для списания
            Если КоличествоВПартии >= Количество Тогда
                ТаблицаРаспределения.Добавить();
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Номенклатура = Номенклатура;
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Партия = Партия;
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Количество = Количество;
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Стоимость = ПартииНоменклатуры[Индекс].Стоимость;
                Количество -= КоличествоВПартии;
                ПартииНоменклатуры[Индекс].Количество -= Количество;
                Если ПартииНоменклатуры[Индекс].Количество = 0 Тогда
                    ТаблицаОстатков.Удалить(Индекс);
                КонецЕсли;
                Прервать;
            Иначе
                ТаблицаРаспределения.Добавить();
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Номенклатура = Номенклатура;
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Партия = Партия;
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Количество = КоличествоВПартии;
                ТаблицаРаспределения[ТаблицаРаспределения.Количество() - 1].Стоимость = ПартииНоменклатуры[Индекс].Стоимость;
                Количество -= КоличествоВПартии;
                ПартииНоменклатуры[Индекс].Количество -= КоличествоВПартии;
                Если ПартииНоменклатуры[Индекс].Количество = 0 Тогда
                    ТаблицаОстатков.Удалить(Индекс);
                КонецЕсли;
            КонецЕсли;
        КонецЦикла;

        // Если после списания остались нереализованные товары
        Если Количество > 0 Тогда
            Исключение = Новый ОписаниеИсключения("Недостаточно остатков для списания номенклатуры " + Номенклатура);
            Бросить(Исключение);
        КонецЕсли;
    КонецЦикла;

    Возврат ТаблицаРаспределения;
