            СписываемаяСтоимость = СписываемоеКоличество * СтоимостьЗаЕдиницу;

            НоваяСтрока = ТаблицаРезультата.Добавить();
            НоваяСтрока.Номенклатура = Номенклатура;
            НоваяСтрока.Партия = Партия;
