            ГДЕ  
                РегистрПартии.Номенклатура = &Номенклатура  
                И РегистрПартии.Склад = &Склад  
            СОРТИРОВАТЬ ПО  
                РегистрПартии.ДатаПартии УБЫВАЮЩЕЕ";

        запрос.УстановитьПараметр("Номенклатура", номенклатура);
        запрос.УстановитьПараметр("Склад", Склад);

        РезультатЗапроса = запрос.Выполнить();

        Если РезультатЗапроса.Пустой() Тогда
            ВытолкнутьИсключение("Недостаточно остатков товара " + номенклатура);
        КонецЕсли;

        остатокПартии = 0;
        общаяСумма = 0;

        Для каждого строкаРезультата Из РезультатЗапроса Цикл
            если остатокПартии < строкаТаблицыТоваров.Количество Тогда
                количествоИзПартии = строкаРезультата.Остаток - остатокПартии;
                стоимостьИзПартии = количествоИзПартии * строкаРезультата.ОценочнаяЦена;

                ТаблицаРаспределения.ДобавитьСтроку();
                ТаблицаРаспределения.Номенклатура = строкаРезультата.Номенклатура;
                ТаблицаРаспределения.Партия = строкаРезультата.Партия;
                ТаблицаРаспределения.Количество = количествоИзПартии;
                ТаблицаРаспределения.Стимость = стоимостьИзПартии;

                остатокПартии += количествоИзПартии;
                общаяСумма += стоимостьИзПартии;

                Если остатокПартии >= строкаТаблицыТоваров.Количество Тогда
                    Прервать;
                КонецЕсли;
            Иначе
                количествоИзПартии = строкаТаблицыТоваров.Количество - остатокПартии;
                стоимостьИзПартии = количествоИзПартии * строкаРезультата.ОценочнаяЦена;

                ТаблицаРаспределения.ДобавитьСтроку();
                ТаблицаРаспределения.Номенклатура = строкаРезультата.Номенклатура;
                ТаблицаРаспределения.Партия = строкаРезультата.Партия;
                ТаблицаРаспределения.Количество = количествоИзПартии;
                ТаблицаРаспределения.Стимость = стоимостьИзПартии;

                общаяСумма += стоимостьИзПартии;
                остатокПартии += количествоИзПартии;
            КонецЕсли;
        КонецЦикла;

        Если остатокПартии > 0 Тогда
            ВытолкнутьИсключение("Недостаточно остатков товара " + номенклатура);
        КонецЕсли;
    КонецЦикла;

    Возврат ТаблицаРаспределения;
