Функция СписатьТоварыFIFO(ТаблицаТоваровКСписанию, Склад) Экспорт

	Распределение = Новый ТаблицаЗначений;
	Распределение.Колонки.Добавить("Номенклатура");
	Распределение.Колонки.Добавить("Партия");
	Распределение.Колонки.Добавить("Количество");
	Распределение.Колонки.Добавить("Стоимость");

	ЗапросПотребность = Новый Запрос;
	ЗапросПотребность.Текст =
	"ВЫБРАТЬ
	|	Товары.Номенклатура КАК Номенклатура,
	|	СУММА(Товары.Количество) КАК Количество
	|ИЗ
	|	&Товары КАК Товары
	|ГДЕ
	|	Товары.Количество > 0
	|СГРУППИРОВАТЬ ПО
	|	Товары.Номенклатура";

	ЗапросПотребность.УстановитьПараметр("Товары", ТаблицаТоваровКСписанию);
	Потребность = ЗапросПотребность.Выполнить().Выгрузить();

	Если Потребность.Количество() = 0 Тогда
		Возврат Распределение;
	КонецЕсли;

	Номенклатуры = Новый Массив;
	ОсталосьСписать = Новый Соответствие;

	Для Каждого СтрокаПотребность Из Потребность Цикл
		Номенклатуры.Добавить(СтрокаПотребность.Номенклатура);
		ОсталосьСписать.Вставить(СтрокаПотребность.Номенклатура, СтрокаПотребность.Количество);
	КонецЦикла;

	ЗапросОстатки = Новый Запрос;
	ЗапросОстатки.Текст =
	"ВЫБРАТЬ
	|	Партии.Номенклатура КАК Номенклатура,
	|	Партии.Партия КАК Партия,
	|	Партии.КоличествоОстаток КАК Количество,
	|	Партии.СтоимостьОстаток КАК Стоимость
	|ИЗ
	|	РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
	|		,
	|		Склад = &Склад
	|			И Номенклатура В (&Номенклатуры)) КАК Партии
	|ГДЕ
	|	Партии.КоличествоОстаток > 0
	|УПОРЯДОЧИТЬ ПО
	|	Партии.Партия.Дата,
	|	Партии.Партия,
	|	Партии.Номенклатура";

	ЗапросОстатки.УстановитьПараметр("Склад", Склад);
	ЗапросОстатки.УстановитьПараметр("Номенклатуры", Номенклатуры);

	ВыборкаОстатки = ЗапросОстатки.Выполнить().Выбрать();

	Пока ВыборкаОстатки.Следующий() Цикл

		Осталось = ОсталосьСписать.Получить(ВыборкаОстатки.Номенклатура);

		Если Осталось = Неопределено Или Осталось <= 0 Тогда
			Продолжить;
		КонецЕсли;

		Если Осталось > ВыборкаОстатки.Количество Тогда
			КоличествоКСписанию = ВыборкаОстатки.Количество;
		Иначе
			КоличествоКСписанию = Осталось;
		КонецЕсли;

		Если КоличествоКСписанию = ВыборкаОстатки.Количество Тогда
			СтоимостьКСписанию = ВыборкаОстатки.Стоимость;
		Иначе
			СтоимостьКСписанию = Окр(КоличествоКСписанию * ВыборкаОстатки.Стоимость / ВыборкаОстатки.Количество, 2);
		КонецЕсли;

		НоваяСтрока = Распределение.Добавить();
		НоваяСтрока.Номенклатура = ВыборкаОстатки.Номенклатура;
		НоваяСтрока.Партия = ВыборкаОстатки.Партия;
		НоваяСтрока.Количество = КоличествоКСписанию;
		НоваяСтрока.Стоимость = СтоимостьКСписанию;

		ОсталосьСписать.Вставить(ВыборкаОстатки.Номенклатура, Осталось - КоличествоКСписанию);

	КонецЦикла;

	Для Каждого СтрокаПотребность Из Потребность Цикл
		Если ОсталосьСписать.Получить(СтрокаПотребность.Номенклатура) > 0 Тогда
			ВызватьИсключение "Недостаточно остатков товара " + Строка(СтрокаПотребность.Номенклатура);
		КонецЕсли;
	КонецЦикла;

	Возврат Распределение;

