			Продолжить;
		КонецЕсли;

		ЗапросВсего.УстановитьПараметр("Склад", Склад);
		ЗапросВсего.УстановитьПараметр("Номенклатура", Стр.Номенклатура);
		РезультатВсего = ЗапросВсего.Выполнить().Выбрать();
		ВесьОстаток = 0;
		Если РезультатВсего.Следующий() Тогда
			ВесьОстаток = РезультатВсего.Всего;
		КонецЕсли;
		Если ЗначениеЗаполнено(ВесьОстаток) = Ложь Тогда
			ВесьОстаток = 0;
		КонецЕсли;

		Если ВесьОстаток < Стр.Количество Тогда
			ВызватьИсключение("Недостаточно остатков номенклатуры: " + Стр.Номенклатура.Наименование);
		КонецЕсли;

		ОстатокКСписанию = Стр.Количество;

		ЗапросПартии.УстановитьПараметр("Склад", Склад);
		ЗапросПартии.УстановитьПараметр("Номенклатура", Стр.Номенклатура);
		ВыборкаПартии = ЗапросПартии.Выполнить().Выбрать();
		Пока ВыборкаПартии.Следующий() И ОстатокКСписанию > 0 Цикл
			ДоступноВПартии = ВыборкаПартии.Количество;
			Если Не ЗначениеЗаполнено(ДоступноВПартии) Тогда
				Продолжить;
			КонецЕсли;
			Если ДоступноВПартии <= 0 Тогда
				Продолжить;
			КонецЕсли;

			Взято = ?(ДоступноВПартии > ОстатокКСписанию, ОстатокКСписанию, ДоступноВПартии);

			ЦенаЕд = 0;
			Если ЗначениеЗаполнено(ВыборкаПартии.Стоимость) И ВыборкаПартии.Количество <> 0 Тогда
				ЦенаЕд = ВыборкаПартии.Стоимость / ВыборкаПартии.Количество;
			КонецЕсли;

			СтоимостьСписания = Взято * ЦенаЕд;

			НоваяСтр = Результат.Добавить();
			НоваяСтр.Номенклатура = Стр.Номенклатура;
			НоваяСтр.Партия = ВыборкаПартии.Партия;
			НоваяСтр.Количество = Взято;
			НоваяСтр.Стоимость = СтоимостьСписания;

			ОстатокКСписанию = ОстатокКСписанию - Взято;
		КонецЦикла;
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция СписатьТоварыFIFO(ТаблицаТоваров, Склад) Экспорт
    // ТаблицаТоваров – ТаблицаЗначений с колонками Номенклатура, Количество
    // Склад – СправочникСсылка.Склады
    // Возврат – ТаблицаЗначений (Номенклатура, Партия, Количество, Стоимость)

    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    Результат.Колонки.Добавить("Партия", Новый ОписаниеТипов("ДокументСсылка.ПоступлениеТоваров"));
    Результат.Колонки.Добавить("Количество", Новый ОписаниеТипов(Тип("Число")));
    Результат.Колонки.Добавить("Стоимость", Новый ОписаниеТипов(Тип("Число")));

    Для Каждого СтрокаТовара Из ТаблицаТоваров Цикл
        Номенклатура = СтрокаТовара.Номенклатура;
        ТребуемоеКол = СтрокаТовара.Количество;

        Запрос = Новый Запрос;
        Запрос.Текст =
        "ВЫБРАТЬ
        |   Остатки.Партия КАК Партия,
        |   Остатки.Количество КАК Количество,
        |   Остатки.Стоимость КАК Стоимость,
        |   Остатки.Партия.Дата КАК ДатаПартии
        |ИЗ
        |   РегистрНакопления.ПартииТоваровНаСкладах КАК Остатки
        |ГДЕ
        |   Остатки.Склад = &Склад
        |   И Остатки.Номенклатура = &Номенклатура
        |   И Остатки.Количество > 0
        |УПОРЯДОЧИТЬ ПО ДатаПартии";
        Запрос.УстановитьПараметр("Склад", Склад);
        Запрос.УстановитьПараметр("Номенклатура", Номенклатура);
        Выборка = Запрос.Выполнить().Выбрать();

        Пока ТребуемоеКол > 0 Цикл
            Если НЕ Выборка.Следующий() Тогда
                ВызватьИсключение("Недостаточно остатков по номенклатуре " + Номенклатура.Наименование);
            КонецЕсли;

            Доступно = Выборка.Количество;
            СписатьКол = Мин(ТребуемоеКол, Доступно);
            ЦенаЗаЕдиницу = 0;
            Если Выборка.Количество <> 0 Тогда
                ЦенаЗаЕдиницу = Выборка.Стоимость / Выборка.Количество;
            КонецЕсли;
            СтоимостьСписания = ЦенаЗаЕдиницу * СписатьКол;

            НовСтрока = Результат.Добавить();
            НовСтрока.Номенклатура = Номенклатура;
            НовСтрока.Партия = Выборка.Партия;
            НовСтрока.Количество = СписатьКол;
            НовСтрока.Стоимость = СтоимостьСписания;

            Движение = Новый Структура;
            Движение.Вставить("Склад", Склад);
            Движение.Вставить("Номенклатура", Номенклатура);
            Движение.Вставить("Партия", Выборка.Партия);
            Движение.Вставить("Количество", -СписатьКол);
            Движение.Вставить("Стоимость", -СтоимостьСписания);
            РегистрНакопления.ПартииТоваровНаСкладах.Записать(Движение);

            ТребуемоеКол = ТребуемоеКол - СписатьКол;
        КонецЦикла;
    КонецЦикла;

    Возврат Результат;
