Функция СписатьТоварыФИФО(ТаблицаТоваров, Склад)

	ТаблицаРезультат = Новый ТаблицаЗначений;
	ТаблицаРезультат.Колонки.Добавить("Номенклатура");
	ТаблицаРезультат.Колонки.Добавить("Партия");
	ТаблицаРезультат.Колонки.Добавить("Количество");
	ТаблицаРезультат.Колонки.Добавить("Стоимость");

	Запрос = Новый Запрос;
	Запрос.МенеджерВременныхТаблиц = Новый МенеджерВременныхТаблиц;
	Запрос.Текст = 
		"ВЫБРАТЬ
		|	ТаблицаТоваров.Номенклатура КАК Номенклатура,
		|	СУММА(ТаблицаТоваров.Количество) КАК Количество
		|ПОМЕСТИТЬ ВТ_Товары
		|ИЗ
		|	&ТаблицаТоваров КАК ТаблицаТоваров
		|СГРУППИРОВАТЬ ПО
		|	ТаблицаТоваров.Номенклатура
		|;
		|
		|////////////////////////////////////////////////////////////////////////////////
		|ВЫБРАТЬ
		|	ВТ_Товары.Номенклатура КАК Номенклатура,
		|	ВТ_Товары.Количество КАК КоличествоСписать,
		|	ПартииТоваровНаСкладахОстатки.Партия КАК Партия,
		|	ЕСТЬNULL(ПартииТоваровНаСкладахОстатки.КоличествоОстаток, 0) КАК КоличествоОстаток,
		|	ЕСТЬNULL(ПартииТоваровНаСкладахОстатки.СтоимостьОстаток, 0) КАК СтоимостьОстаток
		|ИЗ
		|	ВТ_Товары КАК ВТ_Товары
		|		ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
		|				,
		|				Склад = &Склад
		|					И Номенклатура В (ВЫБРАТЬ Номенклатура ИЗ ВТ_Товары)) КАК ПартииТоваровНаСкладахОстатки
		|		ПО ВТ_Товары.Номенклатура = ПартииТоваровНаСкладахОстатки.Номенклатура
		|
		|УПОРЯДОЧИТЬ ПО
		|	ПартииТоваровНаСкладахОстатки.Партия.Дата ВОЗР
		|ИТОГИ
		|	МАКСИМУМ(КоличествоСписать)
		|ПО
		|	Номенклатура";

	Запрос.УстановитьПараметр("ТаблицаТоваров", ТаблицаТоваров);
	Запрос.УстановитьПараметр("Склад", Склад);

	РезультатЗапроса = Запрос.Выполнить();
	ВыборкаНоменклатура = РезультатЗапроса.Выбрать(ОбходРезультатаЗапроса.ПоГруппировкам);

	Пока ВыборкаНоменклатура.Следующий() Цикл

		ОсталосьСписать = ВыборкаНоменклатура.КоличествоСписать;
		ВыборкаПартии = ВыборкаНоменклатура.Выбрать();

		Пока ВыборкаПартии.Следующий() И ОсталосьСписать > 0 Цикл

			Если ВыборкаПартии.КоличествоОстаток <= 0 Тогда
				Продолжить;
			КонецЕсли;

			СписываемоеКоличество = Мин(ОсталосьСписать, ВыборкаПартии.КоличествоОстаток);

			Если СписываемоеКоличество = ВыборкаПартии.КоличествоОстаток Тогда
				СписываемаяСтоимость = ВыборкаПартии.СтоимостьОстаток;
			Иначе
				СписываемаяСтоимость = (ВыборкаПартии.СтоимостьОстаток / ВыборкаПартии.КоличествоОстаток) * СписываемоеКоличество;
			КонецЕсли;

			НоваяСтрока = ТаблицаРезультат.Добавить();
			НоваяСтрока.Номенклатура = ВыборкаПартии.Номенклатура;
			НоваяСтрока.Партия = ВыборкаПартии.Партия;
			НоваяСтрока.Количество = СписываемоеКоличество;
			НоваяСтрока.Стоимость = СписываемаяСтоимость;

			ОсталосьСписать = ОсталосьСписать - СписываемоеКоличество;

		КонецЦикла;

		Если ОсталосьСписать > 0 Тогда
			ВызватьИсключение "Недостаточно остатков для списания номенклатуры: " + Строка(ВыборкаНоменклатура.Номенклатура);
		КонецЕсли;

	КонецЦикла;

	Возврат ТаблицаРезультат;

