		НужноСписать = СтрокаСписания.Количество;
		Номенклатура = СтрокаСписания.Номенклатура;

		Если НужноСписать <= 0 Тогда
			Продолжить;
		КонецЕсли;

		Для Каждого СтрокаОстатка Из ТаблицаОстатков Цикл
			Если СтрокаОстатка.Номенклатура <> Номенклатура Тогда
