			Если Списываем = СтрокаОстатка.КоличествоОстаток Тогда
				СтоимостьСписания = СтрокаОстатка.СтоимостьОстаток;
			Иначе
				СтоимостьСписания = Окр(СтрокаОстатка.СтоимостьОстаток * Списываем / СтрокаОстатка.КоличествоОстаток, 2);
			КонецЕсли;

			НоваяСтрока = Результат.Добавить();
			НоваяСтрока.Номенклатура = Номенклатура;
			НоваяСтрока.Партия = СтрокаОстатка.Партия;
			НоваяСтрока.Количество = Списываем;
			НоваяСтрока.Стоимость = СтоимостьСписания;

			НужноСписать = НужноСписать - Списываем;
			СтрокаОстатка.КоличествоОстаток = СтрокаОстатка.КоличествоОстаток - Списываем;
			СтрокаОстатка.СтоимостьОстаток = СтрокаОстатка.СтоимостьОстаток - СтоимостьСписания;

			Если НужноСписать = 0 Тогда
				Прервать;
			КонецЕсли;
		КонецЦикла;

		Если НужноСписать > 0 Тогда
			ВызватьИсключение "Недостаточно товара на складе: " + Строка(Номенклатура);
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

