Функция СписаниеТоваровFIFO(ТаблицаТоваров, Склад) Экспорт
    // Создаем таблицу результата
    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Номенклатура");
    Результат.Колонки.Добавить("Партия");
    Результат.Колонки.Добавить("Количество");
    Результат.Колонки.Добавить("Стоимость");

    // Копируем таблицу товаров для работы
    ТоварыКСписанию = ТаблицаТоваров.Скопировать();

    // Для каждой позиции товаров к списанию
    Для Каждого СтрокаТовара Из ТоварыКСписанию Цикл
        Номенклатура = СтрокаТовара.Номенклатура;
        Количество = СтрокаТовара.Количество;

        // Получаем остатки партий для данной номенклатуры и склада
        Запрос = Новый Запрос;
        Запрос.УстановитьПараметр("Склад", Склад);
        Запрос.УстановитьПараметр("Номенклатура", Номенклатура);
        Запрос.Текст = "ВЫБРАТЬ
        |    ПартииТоваровНаСкладах.Партия КАК Партия,
        |    ПартииТоваровНаСкладах.Количество КАК Количество,
        |    ПартииТоваровНаСкладах.Стоимость КАК Стоимость,
        |    ПоступлениеТоваров.Дата КАК ДатаПартии
        |ИЗ
        |    РегистрНакопления.ПартииТоваровНаСкладах.Остатки(, Склад = &Склад, Номенклатура = &Номенклатура) КАК ПартииТоваровНаСкладах
        |    ЛЕВОЕ СОЕДИНЕНИЕ Документ.ПоступлениеТоваров КАК ПоступлениеТоваров
        |        ПО ПартииТоваровНаСкладах.Партия = ПоступлениеТоваров.Ссылка
        |УПОРЯДОЧИТЬ ПО
        |    ДатаПартии,
        |    Партия";

        ОстаткиПартий = Запрос.Выполнить().Выгрузить();

        // Проверяем общее количество остатков
        ОбщийОстаток = ОстаткиПартий.Итог("Количество");
        Если ОбщийОстаток < Количество Тогда
            ВызватьИсключение "Недостаточно остатков по номенклатуре: " + Номенклатура.Наименование;
        КонецЕсли;

        ОсталосьСписать = Количество;

        // Списываем FIFO
        Для Каждого СтрокаПартии Из ОстаткиПартий Цикл
            Если ОсталосьСписать <= 0 Тогда
                Прервать;
            КонецЕсли;

            СписываемоеКоличество = Мин(ОсталосьСписать, СтрокаПартии.Количество);

            Если СписываемоеКоличество > 0 Тогда
                // Рассчитываем стоимость пропорционально списываемому количеству
                СтоимостьЕдиницы = ?(СтрокаПартии.Количество <> 0, СтрокаПартии.Стоимость / СтрокаПартии.Количество, 0);
                СтоимостьСписания = СписываемоеКоличество * СтоимостьЕдиницы;

                НоваяСтрока = Результат.Добавить();
                НоваяСтрока.Номенклатура = Номенклатура;
                НоваяСтрока.Партия = СтрокаПартии.Партия;
                НоваяСтрока.Количество = СписываемоеКоличество;
                НоваяСтрока.Стоимость = СтоимостьСписания;

                ОсталосьСписать = ОсталосьСписать - СписываемоеКоличество;
            КонецЕсли;
        КонецЦикла;

        // Проверяем, что все количество списано
        Если ОсталосьСписать > 0 Тогда
            ВызватьИсключение "Недостаточно остатков по номенклатуре: " + Номенклатура.Наименование;
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
