		|	ПартииТоваровНаСкладахОстатки.СтоимостьОстаток КАК СтоимостьОстаток,
		|	ПартииТоваровНаСкладахОстатки.Партия.Дата КАК ДатаПартии
		|ИЗ
		|	РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
		|				,
		|				Склад = &Склад
		|				И Номенклатура В (&СписокНоменклатуры)
		|			) КАК ПартииТоваровНаСкладахОстаток
		|УПОРЯДОЧИТЬ ПО
		|	Номенклатура,
		|	ДатаПартии";

	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("СписокНоменклатуры", СписокНоменклатуры.ВыгрузитьЗначения());

	РезультатЗапроса = Запрос.Выполнить().Выгрузить();

	// Сгруппируем остатки по номенклатуре (уже отсортированы по дате партии)
	ОстаткиПоНоменклатуре = Новый Соответствие;
	Для Каждого СтрокаОстатка Из РезультатЗапроса Цикл
		Ном = СтрокаОстатка.Номенклатура;
		Если ОстаткиПоНоменклатуре[Ном] = Неопределено Тогда
			ОстаткиПоНоменклатуре.Вставить(Ном, Новый Массив);
		КонецЕсли;
		ОстаткиПоНоменклатуре[Ном].Добавить(СтрокаОстатка);
	КонецЦикла;

	// Индексы текущих партий для каждой номенклатуры
	ИндексыПартий = Новый Соответствие;

	// Обрабатываем каждую номенклатуру в порядке исходной таблицы
	Для Каждого СтрокаТовара Из ТаблицаТоваров Цикл

		Ном = СтрокаТовара.Номенклатура;
		КолСписать = СтрокаТовара.Количество;

		ПартииНом = ОстаткиПоНоменклатуре[Ном];

		Если ПартииНом = Неопределено Тогда
			ВызватьИсключение "Недостаточно остатков на складе для номенклатуры: " + Ном.Наименование;
		КонецЕсли;

		Если ИндексыПартий[Ном] = Неопределено Тогда
			ИндексыПартий.Вставить(Ном, 0);
		КонецЕсли;

		ИндПартии = ИндексыПартий[Ном];

		Пока КолСписать > 0 Цикл

			Если ИндПартии >= ПартииНом.Количество() Тогда
				ВызватьИсключение "Недостаточно остатков на складе для номенклатуры: " + Ном.Наименование;
			КонецЕсли;

			СтрокаПартии = ПартииНом[ИндПартии];

			ОстатокКоличество = СтрокаПартии.КоличествоОстаток;
			ОстатокСтоимость = СтрокаПартии.СтоимостьОстаток;

			Если ОстатокКоличество <= 0 Тогда
				ИндексПартии = ИндПартии + 1;
				ИндексыПартий[Ном] = ИндексПартии;
				Продолжить;
			КонецЕсли;

			Если КолСписать <= ОстатокКоличество Тогда
				// Списываем частично
				Если ОстатокКоличество > 0 Тогда
					ЦенаПартии = ОстатокСтоимость / ОстатокКоличество;
				Иначе
					ЦенаПартии = 0;
				КонецЕсли;

				Списано = КолСписать;
