				НоваяСтрока.Партия = СтрокаПартии.Партия;
				НоваяСтрока.Количество = Списано;
				НоваяСтрока.Стоимость = СтоимостьСписания;

				// Уменьшаем остаток в массиве
				СтрокаПартии.КоличествоОстаток = ОстатокКоличество - Списано;
				СтрокаПартии.СтоимостьОстаток = ОстатокСтоимость - СтоимостьСписания;

				КолСписать = 0;
			Иначе
				// Списываем партию полностью
				Если ОстатокКоличество > 0 Тогда
					ЦенаПартии = ОстатокСтоимость / ОстатокКоличество;
				Иначе
					ЦенаПартии = 0;
				КонецЕсли;

				Списано = ОстатокКоличество;
				СтоимостьСписания = ОстатокСтоимость;

				НоваяСтрока = Результат.Добавить();
				НоваяСтрока.Номенклатура = Ном;
				НоваяСтрока.Партия = СтрокаПартии.Партия;
				НоваяСтрока.Количество = Списано;
				НоваяСтрока.Стоимость = СтоимостьСписания;

				КолСписать = КолСписать - Списано;

				// Переходим к следующей партии
				ИндексПартии = ИндПартии + 1;
				ИндексыПартий[Ном] = ИндексПартии;
				ИндПартии = ИндексПартии;
			КонецЕсли;

		КонецЦикла;

	КонецЦикла;

	Возврат Результат;

