Функция СписатьТоварыПоFIFO(ТаблицаТоваров, Склад) Экспорт
	ТаблицаРаспределения = Новый ТаблицаЗначений;
	ТаблицаРаспределения.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	ТаблицаРаспределения.Колонки.Добавить("Партия", Новый ОписаниеТипов("ДокументСсылка.ПоступлениеТоваров"));
	ТаблицаРаспределения.Колонки.Добавить("Количество", Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 3)));
	ТаблицаРаспределения.Колонки.Добавить("Стоимость", Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 2)));

	МассивНоменклатуры = Новый Массив;
	Для Каждого Строка Из ТаблицаТоваров Цикл
		Если МассивНоменклатуры.Найти(Строка.Номенклатура) = Неопределено Тогда
			МассивНоменклатуры.Добавить(Строка.Номенклатура);
		КонецЕсли;
	КонецЦикла;

	Если МассивНоменклатуры.Количество() = 0 Тогда
		Возврат ТаблицаРаспределения;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
	|	ПартииТоваровНаСкладахОстатки.Номенклатура КАК Номенклатура,
	|	ПартииТоваровНаСкладахОстатки.Партия КАК Партия,
	|	ПартииТоваровНаСкладахОстатки.КоличествоОстаток КАК Количество,
	|	ПартииТоваровНаСкладахОстатки.СтоимостьОстаток КАК Стоимость
	|ИЗ
	|	РегистрНакопления.ПартииТоваровНаСкладах.Остатки(, Склад = &Склад И Номенклатура В (&МассивНоменклатуры)) КАК ПартииТоваровНаСкладахОстатки
	|
	|УПОРЯДОЧИТЬ ПО
	|	Номенклатура,
	|	Партия.Дата";
	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
	Остатки = Запрос.Выполнить().Выгрузить();

	ПартииПоНоменклатуре = Новый Соответствие;
	Для Каждого СтрокаОстатка Из Остатки Цикл
		СписокПартий = ПартииПоНоменклатуре[СтрокаОстатка.Номенклатура];
		Если СписокПартий = Неопределено Тогда
			СписокПартий = Новый Массив;
			ПартииПоНоменклатуре.Вставить(СтрокаОстатка.Номенклатура, СписокПартий);
		КонецЕсли;
		СтруктураПартии = Новый Структура("Партия, Количество, Стоимость", СтрокаОстатка.Партия, СтрокаОстатка.Количество, СтрокаОстатка.Стоимость);
		СписокПартий.Добавить(СтруктураПартии);
	КонецЦикла;

	Для Каждого СтрокаСписания Из ТаблицаТоваров Цикл
		Номенклатура = СтрокаСписания.Номенклатура;
		КоличествоКСписанию = СтрокаСписания.Количество;
		Если КоличествоКСписанию <= 0 Тогда
			Продолжить;
		КонецЕсли;

		СписокПартий = ПартииПоНоменклатуре[Номенклатура];
		Если СписокПартий = Неопределено Тогда
			ВызватьИсключение "Недостаточно остатков по номенклатуре: " + Строка(Номенклатура);
		КонецЕсли;

		Индекс = 0;
		Пока КоличествоКСписанию > 0 И Индекс < СписокПартий.Количество() Цикл
			ПартияСтруктура = СписокПартий[Индекс];
			Если ПартияСтруктура.Количество <= 0 Тогда
				Индекс = Индекс + 1;
				Продолжить;
			КонецЕсли;

			Доступно = ПартияСтруктура.Количество;
			Списать = Мин(КоличествоКСписанию, Доступно);
			СтоимостьСписания = Списать * ПартияСтруктура.Стоимость / Доступно;

			НоваяСтрока = ТаблицаРаспределения.Добавить();
			НоваяСтрока.Номенклатура = Номенклатура;
			НоваяСтрока.Партия = ПартияСтруктура.Партия;
			НоваяСтрока.Количество = Списать;
			НоваяСтрока.Стоимость = СтоимостьСписания;

			ПартияСтруктура.Количество = ПартияСтруктура.Количество - Списать;
			ПартияСтруктура.Стоимость = ПартияСтруктура.Стоимость - СтоимостьСписания;
			КоличествоКСписанию = КоличествоКСписанию - Списать;

			Если ПартияСтруктура.Количество <= 0 Тогда
				Индекс = Индекс + 1;
			КонецЕсли;
		КонецЦикла;

		Если КоличествоКСписанию > 0 Тогда
			ВызватьИсключение "Недостаточно остатков по номенклатуре: " + Строка(Номенклатура);
		КонецЕсли;
	КонецЦикла;

	Возврат ТаблицаРаспределения;
КонецФункции

Функция СписатьТоварыFIFO(ТаблицаТоваров, Склад) Экспорт
	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура");
	Результат.Колонки.Добавить("Партия");
	Результат.Колонки.Добавить("Количество");
	Результат.Колонки.Добавить("Стоимость");

	Запрос = Новый Запрос;
	Запрос.Текст =
		"ВЫБРАТЬ
		|	Т.Номенклатура КАК Номенклатура,
		|	Т.Количество КАК Количество
		|ПОМЕСТИТЬ втТовары
		|ИЗ
		|	&ТаблицаТоваров КАК Т
		|;
		|
		|////////////////////////////////////////////////////////////////////////////////
		|ВЫБРАТЬ
		|	Партии.Номенклатура КАК Номенклатура,
		|	Партии.Партия КАК Партия,
		|	Партии.Партия.Дата КАК ДатаПартии,
		|	Партии.КоличествоОстаток КАК Количество,
		|	Партии.СтоимостьОстаток КАК Стоимость
		|ИЗ
		|	РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
		|			,
		|			Склад = &Склад
		|				И Номенклатура В
		|					(ВЫБРАТЬ
		|						вт.Номенклатура
		|					ИЗ
		|						втТовары КАК вт)) КАК Партии
		|
		|УПОРЯДОЧИТЬ ПО
		|	Номенклатура,
		|	ДатаПартии,
		|	Партия
		|ИТОГИ ПО
		|	Номенклатура";
	Запрос.УстановитьПараметр("ТаблицаТоваров", ТаблицаТоваров);
	Запрос.УстановитьПараметр("Склад", Склад);

	ВыборкаНоменклатура = Запрос.Выполнить().Выбрать(ОбходРезультатаЗапроса.ПоГруппировкам);
	СоответствиеОстатков = Новый Соответствие;
	Пока ВыборкаНоменклатура.Следующий() Цикл
		МассивПартий = Новый Массив;
		Выборка = ВыборкаНоменклатура.Выбрать();
		Пока Выборка.Следующий() Цикл
			МассивПартий.Добавить(Новый Структура("Партия,Количество,Стоимость", Выборка.Партия, Выборка.Количество, Выборка.Стоимость));
		КонецЦикла;
		СоответствиеОстатков.Вставить(ВыборкаНоменклатура.Номенклатура, МассивПартий);
	КонецЦикла;

	Для Каждого СтрокаТовар Из ТаблицаТоваров Цикл
		Номенклатура = СтрокаТовар.Номенклатура;
		КПогасить = СтрокаТовар.Количество;
		Партии = СоответствиеОстатков[Номенклатура];
		Если Партии = Неопределено Тогда
			ВызватьИсключение "Недостаточно остатка по номенклатуре: " + Номенклатура;
		КонецЕсли;

		Индекс = 0;
		Пока КПогасить > 0 И Индекс < Партии.Количество() Цикл
			Партия = Партии[Индекс];
			Если Партия.Количество <= 0 Тогда
				Индекс = Индекс + 1;
				Продолжить;
			КонецЕсли;

			Списать = Мин(КПогасить, Партия.Количество);
			Цена = Партия.Стоимость / Партия.Количество;
			Сумма = Цена * Списать;

			НоваяСтрока = Результат.Добавить();
			НоваяСтрока.Номенклатура = Номенклатура;
			НоваяСтрока.Партия = Партия.Партия;
			НоваяСтрока.Количество = Списать;
			НоваяСтрока.Стоимость = Сумма;

			Партия.Количество = Партия.Количество - Списать;
			Партия.Стоимость = Партия.Стоимость - Сумма;
			КПогасить = КПогасить - Списать;
			Индекс = Индекс + 1;
