Функция РассчитатьСебестоимостьСредневзвешенной(МассивНоменклатуры, Склад, Дата) Экспорт

    // Создаём таблицу значений для результата
    ТаблицаРезультат = Новый ТаблицаЗначений;
    ТаблицаРезультат.Колонки.Добавить("Номенклатура");
    ТаблицаРезультат.Колонки.Добавить("СредняяЦена", Новый ОписаниеТипов("Число", , , Новый КвалификаторыЧисла(15, 2)));

    // Если массив номенклатуры пустой — возвращаем пустую таблицу
    Если МассивНоменклатуры = Неопределено Или МассивНоменклатуры.Количество() = 0 Тогда
        Возврат ТаблицаРезультат;
    КонецЕсли;

    // Запрашиваем остатки по регистру накопления
    Запрос = Новый Запрос;
    Запрос.Текст = 
        "ВЫБРАТЬ
        |    Остатки.Номенклатура КАК Номенклатура,
        |    Остатки.КоличествоОстаток КАК Количество,
        |    Остатки.СтоимостьОстаток КАК Стоимость
        |ИЗ
        |    РегистрНакопления.СтоимостьТоваров.Остатки(
        |        &ДатаОстатков,
        |        Склад = &Склад
        |            И Номенклатура В (&МассивНоменклатуры)
        |    ) КАК Остатки";

    Запрос.УстановитьПараметр("ДатаОстатков",     КонецДня(Дата));
    Запрос.УстановитьПараметр("Склад",            Склад);
    Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);

    РезультатЗапроса = Запрос.Выполнить();
    ВыборкаОстатков  = РезультатЗапроса.Выбрать();

    // Помещаем результаты запроса во вспомогательное соответствие
    // для быстрого поиска по номенклатуре
    СоответствиеОстатков = Новый Соответствие;
    Пока ВыборкаОстатков.Следующий() Цикл

        СредняяЦена = 0;
        Если ВыборкаОстатков.Количество <> 0 Тогда
            СредняяЦена = ВыборкаОстатков.Стоимость / ВыборкаОстатков.Количество;
        КонецЕсли;

        СоответствиеОстатков.Вставить(ВыборкаОстатков.Номенклатура, СредняяЦена);

    КонецЦикла;

    // Формируем итоговую таблицу по всем запрошенным позициям
    Для Каждого ЭлементНоменклатуры Из МассивНоменклатуры Цикл

        НоваяСтрока = ТаблицаРезультат.Добавить();
        НоваяСтрока.Номенклатура = ЭлементНоменклатуры;

        СредняяЦенаИзОстатков = СоответствиеОстатков[ЭлементНоменклатуры];
        Если СредняяЦенаИзОстатков <> Неопределено Тогда
            НоваяСтрока.СредняяЦена = СредняяЦенаИзОстатков;
        Иначе
            // Позиция без остатков — средняя цена ноль
            НоваяСтрока.СредняяЦена = 0;
        КонецЕсли;

    КонецЦикла;

    Возврат ТаблицаРезультат;

КонецФункции
