		Если Выборка.КоличествоОстаток <> 0 Тогда
			СредниеЦены.Вставить(
				Выборка.Номенклатура,
				Выборка.СтоимостьОстаток / Выборка.КоличествоОстаток
			);
		Иначе
			СредниеЦены.Вставить(Выборка.Номенклатура, 0);
		КонецЕсли;
	КонецЦикла;

	Для Каждого Номенклатура Из МассивНоменклатуры Цикл
		СтрокаРезультата = Результат.Добавить();
		СтрокаРезультата.Номенклатура = Номенклатура;

		СредняяЦена = СредниеЦены.Получить(Номенклатура);
		Если СредняяЦена = Неопределено Тогда
			СредняяЦена = 0;
		КонецЕсли;

		СтрокаРезультата.СредняяЦена = СредняяЦена;
	КонецЦикла;

	Возврат Результат;

