Процедура ПересчитатьСуммы(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

    // Получение курса и кратности исходной валюты
    Запрос = Новый Запрос;
    Запрос.Текст = 
    "ВЫБРАТЬ
    |	КурсыВалют.Курс,
    |	КурсыВалют.Кратность
    |ИЗ
    |	РегистрСведений.КурсыВалют КАК КурсыВалют
    |ГДЕ
    |	КурсыВалют.Период = &Дата
    |	И КурсыВалют.Валюта = &Валюта";
    Запрос.УстановитьПараметр("Дата", ДатаКурса);
    Запрос.УстановитьПараметр("Валюта", ИсходнаяВалюта);
    Результат = Запрос.Выполнить().Выбрать();
    Если Результат.Следующий() Тогда
        КурсИсх = Результат.Курс;
        КратнИсх = Результат.Кратность;
    Иначе
        ВызватьИсключение "Курс для валюты " + ИсходнаяВалюта.Наименование + " не установлен на дату " + Формат(ДатаКурса, "ДЛФ=ДД");
    КонецЕсли;

    // Получение курса и кратности новой валюты
    Запрос.УстановитьПараметр("Валюта", НоваяВалюта);
    Результат = Запрос.Выполнить().Выбрать();
    Если Результат.Следующий() Тогда
        КурсНов = Результат.Курс;
        КратнНов = Результат.Кратность;
    Иначе
        ВызватьИсключение "Курс для валюты " + НоваяВалюта.Наименование + " не установлен на дату " + Формат(ДатаКурса, "ДЛФ=ДД");
    КонецЕсли;

    // Если валюты совпадают, пересчёт не требуется
    Если ИсходнаяВалюта = НоваяВалюта Тогда
        Возврат;
    КонецЕсли;

    // Расчёт коэффициента пересчёта (цена из исходной в новую)
    Коэффициент = (КурсИсх * КратнНов) / (КурсНов * КратнИсх);

    // Пересчёт строк табличной части
    Для Каждого Строка из Товары Цикл
        Строка.Цена = Строка.Цена * Коэффициент;
        Строка.Сумма = Строка.Цена * Строка.Количество;
    КонецЦикла;

КонецПроцедуры

Процедура ПересчетСуммПриСменеВалюты(ТабличнаяЧасть, ИсходнаяВалюта, НоваяВалюта, ДатаКурса)

	Если ИсходнаяВалюта = НоваяВалюта Тогда
		Возврат;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст = 
"ВЫБРАТЬ
	|	КурсыВалют.Валюта,
	|	КурсыВалют.Курс,
	|	КурсыВалют.Кратность
	|ПОМЕСТИТЬ ВремныеКурсы
	|ИЗ
	|	РегистрСведений.КурсыВалют КАК КурсыВалют
	|ГДЕ
	|	КурсыВалют.Период МЕЖДУ (&ДатаНачала И &ДатаОкончание)
	|	И (КурсыВалют.Валюта = &Валюта1 ИЛИ КурсыВалют.Валюта = &Валюта2)";

	Запрос.УстановитьПараметр("ДатаНачала", НачалоДня(ДатаКурса));
	Запрос.УстановитьПараметр("ДатаОкончание", КонецДня(ДатаКурса));
	Запрос.УстановитьПараметр("Валюта1", ИсходнаяВалюта);
	Запрос.УстановитьПараметр("Валюта2", НоваяВалюта);

	РезультатЗапроса = Запрос.Выполнить();
	ТаблицаКурсов = РезультатЗапроса.Выгрузить();

	Если ТаблицаКурсов.Количество() < 2 Тогда
		Для Каждого Стр Из ТаблицаКурсов Цикл
			Если Стр.Валюта = ИсходнаяВалюта Тогда
				КурсИсходнойНайден = Истина;
			КонецЕсли;
			Если Стр.Валюта = НоваяВалюта Тогда
				КурсНовойНайден = Истина;
			КонецЕсли;
		КонецЦикла;

		Если Не ЗначениеЗаполнено(КурсИсходнойНайден) Тогда
			ВызватьИсключение "Не найден курс валюты " + ИсходнаяВалюта.Наименование() + " на дату " + ДатаКурса;
		КонецЕсли;

		Если Не ЗначениеЗаполнено(КурсНовойНайден) Тогда
			ВызватьИсключение "Не найден курс валюты " + НоваяВалюта.Наименование() + " на дату " + ДатаКурса;
		КонецЕсли;
	КонецЕсли;

	КурсИсходной = ?(ИсходнаяВалюта.ЕстьПотомки(), 1, 
		ТаблицаКурсов.Найти(ИсходнаяВалюта).Курс / ТаблицаКурсов.Найти(ИсходнаяВалюта).Кратность);
	КурсНовой = ?(НоваяВалюта.ЕстьПотомки(), 1, 
		ТаблицаКурсов.Найти(НоваяВалюта).Курс / ТаблицаКурсов.Найти(НоваяВалюта).Кратность);

	КроссКурс = КурсИсходной / КурсНовой;

	Для Каждого Строка Из ТабличнаяЧасть Цикл
		СтараяСумма = Строка.Сумма;
		НоваяЦена = Окр(Строка.Цена / КроссКурс, 2);
		НоваяСумма = Окр(НоваяЦена * Строка.Количество, 2);

		Строка.Цена = НоваяЦена;
		Строка.Сумма = НоваяСумма;
	КонецЦикла;

КонецПроцедуры

Процедура ПересчитатьСуммы(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

    Запрос = Новый Запрос;
    Запрос.Текст = "ВЫБРАТЬ
                   | КурсыВалют.Курс,
                   | КурсыВалют.Кратность
                   |ИЗ
                   | РегистрСведений.КурсыВалют КАК КурсыВалют
                   |ГДЕ
                   | КурсыВалют.Валюта = &Валюта
                   | И КурсыВалют.Период <= &ДатаКурса";

    Запрос.УстановитьПараметр("Валюта", ИсходнаяВалюта);
    Запрос.УстановитьПараметр("ДатаКурса", ДатаКурса);
    Результат = Запрос.Выполнить();
    ВыборкаИсходная = Результат.Выбрать();
    Если Не ВыборкаИсходная.Следующий() Тогда
        ВызватьИсключение "Для валюты '" + ИсходнаяВалюта + "' отсутствует курс на дату " + Формат(ДатаКурса, "ДФ=dd.MM.yyyy");
    КонецЕсли;

    Запрос.УстановитьПараметр("Валюта", НоваяВалюта);
    Результат = Запрос.Выполнить();
    ВыборкаНовая = Результат.Выбрать();
    Если Не ВыборкаНовая.Следующий() Тогда
        ВызватьИсключение "Для валюты '" + НоваяВалюта + "' отсутствует курс на дату " + Формат(ДатаКурса, "ДФ=dd.MM.yyyy");
    КонецЕсли;

    Для Каждого СтрокаТовары Из Товары Цикл
        // Пересчет цены через кросс-курс: НоваяЦена = СтараяЦена * (КурсНовой / КурсИсходной)
