        ВызватьИсключение "Не найден курс валюты: " + НоваяВалюта.Наименование;
    КонецЕсли;

    ВыборкаНовой = РезультатНовой.Выбрать();
    ВыборкаНовой.Следующий();

    КурсНовой      = ВыборкаНовой.Курс;
    КратностьНовой = ВыборкаНовой.Кратность;

    Если КурсНовой = 0 ИЛИ КратностьНовой = 0 Тогда
        ВызватьИсключение "Некорректный курс (ноль) для валюты: " + НоваяВалюта.Наименование;
