Процедура ПересчитатьСуммыПриСменеВалюты(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

	ДанныеИсходнойВалюты = ПолучитьДанныеКурсаВалюты(ИсходнаяВалюта, ДатаКурса);
	ДанныеНовойВалюты = ПолучитьДанныеКурсаВалюты(НоваяВалюта, ДатаКурса);

	КоэффициентПересчета = (ДанныеИсходнойВалюты.Курс / ДанныеИсходнойВалюты.Кратность) 
		/ (ДанныеНовойВалюты.Курс / ДанныеНовойВалюты.Кратность);

	Для Каждого СтрокаТоваров Из Товары Цикл
		СтрокаТоваров.Цена = Окр(СтрокаТоваров.Цена * КоэффициентПересчета, 2);
		СтрокаТоваров.Сумма = Окр(СтрокаТоваров.Сумма * КоэффициентПересчета, 2);
	КонецЦикла;

КонецПроцедуры

Процедура ПересчитатьСуммы(Товары, ВалютаИсходная, ВалютаНовая, ДатаКурса)
	// Валидация
	Если ВалютаИсходная = Неопределено Или ВалютаНовая = Неопределено Тогда
		Ошибка("Не указана валюта");
	КонецЕсли;
	Если ВалютаИсходная = ВалютаНовая Тогда
		Возврат;
	КонецЕсли;

	КурсИсх = ПолучитьКурсВалюты(ВалютаИсходная, ДатаКурса);
	КурсНов  = ПолучитьКурсВалюты(ВалютаНовая, ДатаКурса);

	// Кросс-курс: (курсИсх/кратностьИсх) / (курсНов/кратностьНов)
	Если КурсНов.Курс = 0 Тогда
		Ошибка("Нет курса для валюты " + ВалютаНовая.Наименование);
	КонецЕсли;
	КроссКурс = (КурсИсх.Курс * КурсНов.Кратность) / (КурсНов.Курс * КурсИсх.Кратность);

	Для Каждого Строка Из Товары Цикл
		Если ЗначениеЗаполнено(Строка.Цена) Тогда
			НоваяЦена = Округлить(Строка.Цена * КроссКурс, 2);
		Иначе
			НоваяЦена = 0;
		КонецЕсли;
		Строка.Цена = НоваяЦена;
		Строка.Сумма = Округлить(Строка.Цена * Строка.Количество, 2);
	КонецЦикла;
КонецПроцедуры

Функция ПолучитьКурсВалюты(Валюта, ДатаКурса)
	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ ПЕРВЫЕ 1
		КурсВалют.Курс КАК Курс,
		КурсВалют.Кратность КАК Кратность
	ИЗ
		РегистрСведений.КурсыВалют КАК КурсВалют
	ГДЕ
		КурсВалют.Валюта = &Валюта
		И КурсВалют.Период <= &Дата
	УПОРЯДОЧИТЬ ПО
		КурсВалют.Период УБЫВ";
	Запрос.УстановитьПараметр("Валюта", Валюта);
	Запрос.УстановитьПараметр("Дата", ДатаКурса);

	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();
	Если НЕ Выборка.Следующий() Тогда
		Ошибка("Нет курса для валюты " + Валюта.Наименование);
	КонецЕсли;

	КурсСтр = Новый Структура;
	КурсСтр.Вставить("Курс",     Выборка.Курс);
	КурсСтр.Вставить("Кратность", Выборка.Кратность);
	Возврат КурсСтр;
