// Процедура пересчёта сумм документа при смене валюты
Процедура ПересчитатьСуммы(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса)
    // Получаем курс исходной валюты к базовой
    КурсИсх = ПолучитьКурс(ИсходнаяВалюта, ДатаКурса);
    // Получаем курс новой валюты к базовой
    КурсНов = ПолучитьКурс(НоваяВалюта, ДатаКурса);

    // Кросс‑курс (новая/исходная)
    КроссКурс = (КурсНов.Курс / КурсНов.Кратность) / (КурсИсх.Курс / КурсИсх.Кратность);

    // Пересчитываем строки табличной части
    Для каждого Строка Товары Цикл
        // Пересчёт цены
        Если Строка.Цена <> Неопределено Тогда
            Строка.Цена = Строка.Цена * КроссКурс;
        Иначе
            Строка.Цена = 0;
        КонецЕсли;

        // Пересчёт суммы
        Строка.Сумма = Строка.Количество * Строка.Цена;
    КонецЦикла;
КонецПроцедуры

