Процедура ПересчитатьСуммыДокументаПриСменеВалюты(ТабличнаяЧасть, ВалютаИсходная, ВалютаНовая, ДатаКурса) Экспорт

	// Получаем курс и кратность исходной валюты на указанную дату
	Отбор = Новый Структура("Валюта", ВалютаИсходная);
	РезультатИсходная = РегистрыСведений.КурсыВалют.СрезПоследних(ДатаКурса, Отбор);

	Если РезультатИсходная.Количество() = 0 Тогда
		ВызватьИсключение "Не найден курс валюты """ + ВалютаИсходная + """ на дату " + Формат(ДатаКурса, "ДЛФ=D") + ".";
	КонецЕсли;

	КурсИсходный    = РезультатИсходная[0].Курс;
	КратностьИсходная = РезультатИсходная[0].Кратность;

	Если КурсИсходный = 0 Или КратностьИсходная = 0 Тогда
		ВызватьИсключение "Не найден курс валюты """ + ВалютаИсходная + """ на дату " + Формат(ДатаКурса, "ДЛФ=D") + ".";
	КонецЕсли;

	// Получаем курс и кратность новой валюты на указанную дату
	Отбор = Новый Структура("Валюта", ВалютаНовая);
	РезультатНовая = РегистрыСведений.КурсыВалют.СрезПоследних(ДатаКурса, Отбор);

	Если РезультатНовая.Количество() = 0 Тогда
		ВызватьИсключение "Не найден курс валюты """ + ВалютаНовая + """ на дату " + Формат(ДатаКурса, "ДЛФ=D") + ".";
	КонецЕсли;

	КурсНовый     = РезультатНовая[0].Курс;
	КратностьНовая = РезультатНовая[0].Кратность;

	Если КурсНовый = 0 Или КратностьНовая = 0 Тогда
		ВызватьИсключение "Не найден курс валюты """ + ВалютаНовая + """ на дату " + Формат(ДатаКурса, "ДЛФ=D") + ".";
	КонецЕсли;

	// Кросс-курс пересчёта: сколько единиц новой валюты соответствует одной единице исходной валюты
	КроссКурс = (КурсИсходный / КратностьИсходная) / (КурсНовый / КратностьНовая);

	// Пересчёт цен и сумм по строкам табличной части
	Для Каждого СтрокаТовара Из ТабличнаяЧасть Цикл

		СтрокаТовара.Цена = Округл(СтрокаТовара.Цена * КроссКурс, 2);
		СтрокаТовара.Сумма = Округл(СтрокаТовара.Цена * СтрокаТовара.Количество, 2);

	КонецЦикла;

