Процедура ПересчитатьСуммыПриСменеВалюты(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

	Валюты = Новый Массив;
	Валюты.Добавить(ИсходнаяВалюта);

	Если ИсходнаяВалюта <> НоваяВалюта Тогда
		Валюты.Добавить(НоваяВалюта);
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	КурсыВалютСрезПоследних.Валюта КАК Валюта,
	|	КурсыВалютСрезПоследних.Курс КАК Курс,
	|	КурсыВалютСрезПоследних.Кратность КАК Кратность
	|ИЗ
	|	РегистрСведений.КурсыВалют.СрезПоследних(&ДатаКурса, Валюта В (&Валюты)) КАК КурсыВалютСрезПоследних";

	Запрос.УстановитьПараметр("ДатаКурса", ДатаКурса);
	Запрос.УстановитьПараметр("Валюты", Валюты);

	КурсыВалют = Новый Соответствие;

	Выборка = Запрос.Выполнить().Выбрать();
	Пока Выборка.Следующий() Цикл
		КурсыВалют.Вставить(Выборка.Валюта, Новый Структура("Курс,Кратность", Выборка.Курс, Выборка.Кратность));
	КонецЦикла;

	КурсИсходнойВалюты = КурсыВалют.Получить(ИсходнаяВалюта);
	Если КурсИсходнойВалюты = Неопределено Тогда
		ВызватьИсключение "Не найден курс валюты: " + ИсходнаяВалюта.Наименование;
	КонецЕсли;

	КурсНовойВалюты = КурсыВалют.Получить(НоваяВалюта);
	Если КурсНовойВалюты = Неопределено Тогда
		ВызватьИсключение "Не найден курс валюты: " + НоваяВалюта.Наименование;
	КонецЕсли;

	Если КурсИсходнойВалюты.Кратность = 0 Или КурсНовойВалюты.Курс = 0 Или КурсНовойВалюты.Кратность = 0 Тогда
		ВызватьИсключение "Некорректный курс валюты: " + НоваяВалюта.Наименование;
	КонецЕсли;

	КоэффициентПересчета = (КурсИсходнойВалюты.Курс / КурсИсходнойВалюты.Кратность)
		/ (КурсНовойВалюты.Курс / КурсНовойВалюты.Кратность);

	Для Каждого СтрокаТоваров Из Товары Цикл
		СтрокаТоваров.Цена = СтрокаТоваров.Цена * КоэффициентПересчета;
		СтрокаТоваров.Сумма = СтрокаТоваров.Количество * СтрокаТоваров.Цена;
	КонецЦикла;

