	ТаблицаОборотов.Колонки.Добавить("Количество", Тип("Число"));
	ТаблицаОборотов.Колонки.Добавить("Сумма", Тип("Число"));

	Запрос = Новый Запрос;
	ЗапросТекст = "ВЫБРАТЬ 
		РегистрНакопления.ОборотыПоПродажамНоменклатуры.Номенклатура,
		СУММА(РегистрНакопления.ОборотыПоПродажамНоменклатуры.Количество) КАК Количество,
		СУММА(РегистрНакопления.ОборотыПоПродажамНоменклатуры.Сумма) КАК Сумма
	PO РегистрНакопления.ОборотыПоПродажамНоменклатуры
	GДЕ РегистрНакопления.ОборотыПоПродажамНоменклатуры.Период МЕЖДУ &ДатаНачалаПериода И &ДатаКонцаПериода";

	Если Склад <> Неопределено Тогда
		ЗапросТекст += " И РегистрНакопления.ОборотыПоПродажамНоменклатуры.Склад = &Склад"
	КонецЕсли;

	ЗапросТекст += " СГРУППИРОВАТЬ ПО РегистрНакопления.ОборотыПоПродажамНоменклатуры.Номенклатура";
