    ТаблицаРезультатов = Новый ТаблицаЗначений;
    ТаблицаРезультатов.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    ТаблицаРезультатов.Колонки.Добавить("НачальныйОстаток", Новый ОписаниеТипов("Число"));
    ТаблицаРезультатов.Колонки.Добавить("Приход", Новый ОписаниеТипов("Число"));
    ТаблицаРезультатов.Колонки.Добавить("Расход", Новый ОписаниеТипов("Число"));
    ТаблицаРезультатов.Колонки.Добавить("КонечныйОстаток", Новый ОписаниеТипов("Число"));

