        ВЫБРАТЬ
            ДвиженияТоваров.Номенклатура КАК Номенклатура,
            СУММА(ВЫБОР
                КОГДА ДвиженияТоваров.Период < &НачалоПериода
                    ТОГДА ДвиженияТоваров.Количество
                ИНАЧЕ 0
            КОНЕЦ) КАК НачальныйОстаток,
            СУММА(ВЫБОР
                КОГДА ДвиженияТоваров.Период >= &НачалоПериода И ДвиженияТоваров.Период <= &КонецПериода И ДвиженияТоваров.Количество >  Normally
                    ТОГДА ДвиженияТоваров.Количество
                ИНАЧЕ 0
            КОНЕЦ) КАК Приход,
            СУММА(ВЫБОР
                КОГДА ДвиженияТоваров.Период >= &НачалоПериода И ДвиженияТоваров.Период <= &КонецПериода И ДвиженияТоваров.Количество < 0
                    ТОГДА -ДвиженияТоваров.Количество
                ИНАЧЕ 0
            КОНЕЦ) КАК Расход
        ИЗ
            РегистрНакопления.ДвиженияТоваров.Обороты(&НачалоПериода, &КонецПериода) КАК ДвиженияТоваров
        ГДЕ
            ВЫБОР
                КОГДА &Склад = НЕОПРЕДЕЛЕНО
                    ТОГДА ИСТИНА
                ИНАЧЕ ДвиженияТоваров.Склад = &Склад
            КОНЕЦ
        СГРУППИРОВАТЬ ПО
            ДвиженияТоваров.Номенклатура
    ";

    Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
    Запрос.УстановитьПараметр("КонецПериода", КонецПериода);
    Запрос.УстановитьПараметр("Склад", Склад);

    РезультатЗапроса = Запрос.Выполнить();
    Выборка = РезультатЗапроса.Выбрать();

