        СтрокаТаблицы = ТаблицаРезультатов.Добавить();
        СтрокаТаблицы.Номенклатура = Выборка.Номенклатура;
        СтрокаТаблицы.НачальныйОстаток = Выборка.НачальныйОстаток;
        СтрокаТаблицы.Приход = Выборка.Приход;
        СтрокаТаблицы.Расход = Выборка.Расход;
