			ГДЕ 
				Приход.ВидДвижения = ЗНАЧЕНИЕ(Перечисление.ВидыДвиженийПриходы)
				#Если ПустоеЗначение(&Склад, "") Тогда ""
				И Приход.Склад = &Склад
				#КонецЕсли
			СГРУППИРОВАТЬ ПО 
				Приход.Номенклатура) КАК ВТПриход ПО
		ВТПриход.Номенклатура = Номенклатура.Ссылка
		ЛЕВОЕ СОЕДИНЕНИЕ 
			(ВЫБРАТЬ 
				Расход.Номенклатура,
				СУММА(Расход.Количество) КАК ИтогоКоличество
			ИЗ 
				Rgtn.DvжениеОстатковНаСкладе(&ДатаНачалаПериода, &ДатаКонцаПериода, , ) КАК Расход
			ГДЕ 
				Расход.ВидДвижения = ЗНАЧЕНИЕ(Перечисление.ВидыДвиженийРасходы)
