Функция ПолучитьОстаткиНоменклатуры(НачалоПериода, КонецПериода, Склад) Экспорт
// Создаем таблицу значений для результата
ТаблицаРезультата = Новый ТаблицаЗначений;
ТаблицаРезультата.Колонки.Добавить("Номенклатура");
ТаблицаРезультута.Колонки.Добавить("НачальныйОстаток");
ТаблицаРезультута.Колонки.Добавить("Приход");
ТаблицаРезультута.Колонки.Добавить("Расход");
ТаблицаРезультута.Колонки.Добавить("КонечныйОстаток");

// Получаем список всех номенклатур
СписокНоменклатур = Справочник.Номенклатура.ПолучитьВыбранныеЭлементы();

Для Каждого Номенклатура Из СписокНоменклатур Цикл
Запрос = Новый Запрос;
Запрос.Текст =
"ВЫБРАТЬ
    Номенклатура.Код,
    Номенклатура.Наименование
ИЗ
    Справочник.Номенклатура КАК Номенклатура";

РезультатЗапроса = Запрос.Выполнить().Выбрать();

Если РезультатЗапроса.Следующий() Тогда
СтрокаТаблицы = ТаблицаРезультата.Добавить();
СтрокаТаблицы."Номенклатура" = РезультатЗапроса.Код + " - " + РезультатЗапроса.Наименование;

Запрос = Новый Запрос;
Запрос.Текст =
"ВЫБРАТЬ
    ОстатокНА.Склад,
    ОстатокНА.Остаток НА КАК НачальныйОстаток,
    СУММ(Документ.ПриходныйСкладскойДокумент.ПоступлениеТоваровУслуг.СуммаПоНоменклатуре) КАК Приход,
    СУММ(Документ.РасходныйСкладскойДокумент.СуммаПоНоменклатуре) КАК Расход
ИЗ
    РегистрНакопления.ОстаткиНА КАК ОстатокNA
    ЛЕВОЕ СОЕДИНЕНИЕ Документ.ПриходныйСкладскойДокумент КАК ПрихОДНЫЙСКЛАДСКОЙДОКУМЕНТ
        ПО ОстатокNA.Склад = ПрихОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Склад И ОстатокNA.Номенклатура = ПрихОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Номенклатура
    ЛЕВОЕ СОЕДИНЕНИЕ Документ.РасходныйСкладскойДокумент КАК РасХОДНЫЙСКЛАДСКОЙДОКУМЕНТ
        ПО ОстатокNA.Склад = РасХОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Склад И ОстатокNA.Номенклатура = РасХОДНЫЙСКЛАДСКОЙДОКУМЕНТ.Номенклатура
ГДЕ
    ОстатокNA.Склад = &Склад
И ОстатокNA.Период С <= &НачалоПериода
И ОстатокNA.Период К >= &КонецПериода
УПОРЯДОЧИТЬ ПО
    ОстатокNA.Номенклатура";

Если Параметр(Склад) <> Неопределено Тогда
Запрос.УстановитьПараметр("Склад", Склад);
КонецЕсли;

Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
Запрос.УстановитьПараметр("КонецПериода", КонецПериода);

РезультатЗапроса = Запрос.Выполнить();

Если РезультатЗапроса.Первый() Тогда
СтрокаТаблицы."НачальныйОстаток" = РезультатЗапроса.НачальныйОстаток;
СтрокаТаблицы."Приход" = РезультатЗапроса.Приход;
СтрокаТаблицы."Расход" = РезультатЗапроса.Расход;
СтрокаТаблицы."КонечныйОстаток" = СтрокаТаблицы."НачальныйОстаток" + СтрокаТаблицы."Приход" - СтрокаТаблицы."Расход";
Иначе
СтрокаТаблицы."НачальныйОстаток" = 0;
СтрокаТаблицы."Приход" = 0;
СтрокаТаблицы."Расход" = 0;
СтрокаТаблицы."КонечныйОстаток" = 0;
КонецЕсли;
КонецЕсли;
КонецЦикла;
Возврат ТаблицаРезультата;
КонецФункции

