		СУММА(ВЫБОР КОГДА ДвиженияТоваров.Период >= &НачалоПериода И ДвиженияТоваров.Период <= &КонецПериода И ДвиженияТоваров.Количество > 0 ТОГДА ДвиженияТоваров.Количество ИНАЧЕ 0 КОНЕЦ) КАК Приход,
		СУММА(ВЫБОР КОГДА ДвиженияТоваров.Период >= &НачалоПериода И ДвиженияТоваров.Период <= &КонецПериода И ДвиженияТоваров.Количество < 0 ТОГДА -ДвиженияТоваров.Количество ИНАЧЕ 0 КОНЕЦ) КАК Расход,
		СУММА(ВЫБОР КОГДА ДвиженияТоваров.Период <= &КонецПериода ТОГДА ДвиженияТоваров.Количество ИНАЧЕ 0 КОНЕЦ) КАК КонечныйОстаток
	ИЗ РегистрНакопления.ДвиженияТоваров КАК ДвиженияТоваров";

	Если Склад <> Неопределено Тогда
		ТекстЗапроса = ТекстЗапроса + "
	ГДЕ ДвиженияТоваров.Склад = &Склад";
	КонецЕсли;

	ТекстЗапроса = ТекстЗапроса + "
	СГРУППИРОВАТЬ ПО ДвиженияТоваров.Номенклатура";

	Запрос.Текст = ТекстЗапроса;
	Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
	Запрос.УстановитьПараметр("КонецПериода", КонецПериода);
	Если Склад <> Неопределено Тогда
		Запрос.УстановитьПараметр("Склад", Склад);
	КонецЕсли;

	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	Таблица = Новый ТаблицаЗначений;
	Таблица.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
