Функция СводТоваров(СсылкаДокумента)
	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	Результат.Колонки.Добавить("Количество", Новый ОписаниеТипов("Число"));
	Результат.Колонки.Добавить("Сумма", Новый ОписаниеТипов("Число"));

	Если НЕ ЗначениеЗаполнено(СсылкаДокумента) Тогда
		Возврат Результат;
	КонецЕсли;

	Попытка
		ДокОбъект = Документы.ЗаказПокупателя.ПолучитьОбъект(СсылкаДокумента);
	Исключение
		Возврат Результат;
	КонецПопытки;

	Соотв = Новый Соответствие;
	Для Каждого Стр Из ДокОбъект.Товары Цикл
		Ном = Стр.Номенклатура;
		Если НЕ Соотв.Содержит(Ном) Тогда
			Агр = Новый Структура("Количество, Сумма", 0, 0);
			Соотв.Вставить(Ном, Агр);
		Иначе
			Агр = Соотв.Получить(Ном);
		КонецЕсли;

		Если ЗначениеЗаполнено(Стр.Количество) Тогда
			Агр.Количество = Агр.Количество + Стр.Количество;
		EndIf;
		Если ЗначениеЗаполнено(Стр.Сумма) Тогда
			Агр.Сумма = Агр.Сумма + Стр.Сумма;
		EndIf;

		Соотв.Вставить(Ном, Агр);
	КонецЦикла;

	Для Каждого Ключ Из Соотв.Ключи() Цикл
		Агр = Соотв.Получить(Ключ);
		НоваяСтрока = Результат.Добавить();
		НоваяСтрока.Номенклатура = Ключ;
		НоваяСтрока.Количество = Округлить(Агр.Количество, 3);
		НоваяСтрока.Сумма = Округлить(Агр.Сумма, 2);
	КонецЦикла;

	Возврат Результат;
КонецФункции

Функция СвестиТоварыПоНоменклатуре(ДокСсылка) Экспорт
    // ДокСсылка – ссылка на документ ЗаказПокупателя
    ТаблицаИтогов = Новый ТаблицаЗначений;
    ТаблицаИтогов.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    ТаблицаИтогов.Колонки.Добавить("Количество", Новый ОписаниеТипов("Число",,15,3));
    ТаблицаИтогов.Колонки.Добавить("Сумма", Новый ОписаниеТипов("Число",,15,2));

    Если Не ДокСсылка Пустая() Тогда
        ОбъектДок = ДокСсылка.ПолучитьОбъект();
        Если ОбъектДок <> Неопределено Тогда
            Товары = ОбъектДок.Товары;
            СоответствиеСтрок = Новый Соответствие; // Ключ – ссылка на номенклатуру, значение – индекс строки в ТаблицаИтогов

            Для каждого Стр Из Товары Цикл
                Ключ = Стр.Номенклатура;
                Если СоответствиеСтрок.Содержит(Ключ) Тогда
                    Индекс = СоответствиеСтрок[Ключ];
                    ТаблицаИтогов[Индекс].Количество = ТаблицаИтогов[Индекс].Количество + Стр.Количество;
                    ТаблицаИтогов[Индекс].Сумма = ТаблицаИтогов[Индекс].Сумма + Стр.Сумма;
                Иначе
                    НоваяСтрока = ТаблицаИтогов.Добавить();
                    НоваяСтрока.Номенклатура = Ключ;
                    НоваяСтрока.Количество = Стр.Количество;
                    НоваяСтрока.Сумма = Стр.Сумма;
                    // Индекс только что добавленной строки
                    СоответствиеСтрок.Вставить(Ключ, ТаблицаИтогов.Количество() - 1);
                КонецЕсли;
            КонецЦикла;
        КонецЕсли;
    КонецЕсли;

    Возврат ТаблицаИтогов;
КонецФункции

