Функциция СводТоваровЗаказа(ЗаказПокупателя)

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	Результат.Колонки.Добавить("Количество", Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 3)));
	Результат.Колонки.Добавить("Сумма", Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 2)));

	Если ЗаказПокупателя = Неопределено
	   Или ЗаказПокупателя.Пустая() Тогда
		Возврат Результат;
	КонецЕсли;

	ОбъектДок = ЗаказПокупателя.ПолучитьОбъект();

	Для Каждого СтрокаТЧ Из ОбъектДок.Товары Цикл

		Ном = СтрокаТЧ.Номенклатура;
		Если Ном = Неопределено Или Ном.Пустая() Тогда
			Продолжить;
		КонецЕсли;

		НайденнаяСтрока = Результат.Найти(Ном, "Номенклатура");

		Если НайденнаяСтрока = Неопределено Тогда
			НоваяСтрока = Результат.Добавить();
			НоваяСтрока.Номенклатура = Ном;
			НоваяСтрока.Количество  = СтрокаТЧ.Количество;
			НоваяСтрока.Сумма       = СтрокаТЧ.Сумма;
		Иначе
			НайденнаяСтрока.Количество = НайденнаяСтрока.Количество + СтрокаТЧ.Количество;
			НайденнаяСтрока.Сумма      = НайденнаяСтрока.Сумма + СтрокаТЧ.Сумма;
		КонецЕсли;

	КонецЦикла;

	Возврат Результат;

КонецФункции
